    ('SOAD-C 381', 'TOPICAL ISSUES IN COLLABORATIVE DESIGN', '10166', 'Class Status', 'MW Monday, Wednesday 12:45 PM–3:30 PM', 'KH 017', 'Maxwell Fertik', 8, NULL, 'Lecture', '3', 'KIRKWOOD HALL', ARRAY[]::TEXT[], 'Employs design thinking strategies to understand challenges facing a community partner. The class will then focus on a co-design participatory approach, with project partners to offer solutions to the project. Classes may partner with regional organizations and companies.', ARRAY[]::TEXT[], NULL),
