    ('SOAD-F 213', 'FASHION DESIGN I: RESEARCH AND ILLUSTRATION', '3636', 'Class Status', 'MW Monday, Wednesday 9:10 AM–11:55 AM', 'KH 302', 'Jessica Quirk', 4, NULL, 'Laboratory', '3', 'KIRKWOOD HALL', ARRAY[]::TEXT[], 'Exploration of design inspiration and precedent research methods. Use of various media to communicate fashion design through technical drawing and illustration.', ARRAY[]::TEXT[], NULL),
