    ('SOAD-F 213', 'FASHION DESIGN I: RESEARCH AND ILLUSTRATION', '11456', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–5:05 PM', 'KH 302', 'Megan Romans', 6, NULL, 'Laboratory', '3', 'KIRKWOOD HALL', ARRAY[]::TEXT[], 'Exploration of design inspiration and precedent research methods. Use of various media to communicate fashion design through technical drawing and illustration.', ARRAY[]::TEXT[], NULL),
    ('SOAD-F 301', 'FASHION STUDIES: TOPICS IN CULTURAL ANALYSIS', '12473', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'KH 318', 'Cydni Robertson', 0, NULL, 'Lecture', '3', 'KIRKWOOD HALL', ARRAY[]::TEXT[], 'Dress as a reflection of the physical, social, psychological, and aesthetic environment of various non-US cultures; responses to and uses of dress as an aspect of global culture and individual behavior. Topics vary.', ARRAY['COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('SOAD-F 305', 'FASHION STUDIO III', '8508', 'Class Status', 'MW Monday, Wednesday 12:45 PM–3:30 PM', 'KH 313', 'Deborah Christiansen', 6, NULL, 'Laboratory', '3', 'KIRKWOOD HALL', ARRAY[]::TEXT[], 'Advanced pattern development, fitting, fabric manipulation, and construction of original fashion designs. Studio class.', ARRAY[]::TEXT[], NULL),
    ('SOAD-F 305', 'FASHION STUDIO III', '14380', 'Class Status', 'MW Monday, Wednesday 12:45 PM–3:30 PM', 'KH 305', 'Lori Frye', 3, NULL, 'Laboratory', '3', 'KIRKWOOD HALL', ARRAY[]::TEXT[], 'Advanced pattern development, fitting, fabric manipulation, and construction of original fashion designs. Studio class.', ARRAY[]::TEXT[], NULL),
    ('SOAD-F 311', 'HISTORY OF DRESS', '33336', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'KH 318', 'Nicole Rudolph', 0, NULL, 'Lecture', '3', 'KIRKWOOD HALL', ARRAY[]::TEXT[], 'Dress in Western civilization relating to social, economic, political, and religious events from early civilization through seventeenth century.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('SOAD-F 312', 'FASHION STUDIES: AUTOBIOGRAPHIES OF DRESS AND THE BODY', '14382', 'Closed', 'MW Monday, Wednesday 9:10 AM–11:55 AM', 'KH 318', 'Heather Akou', 0, NULL, 'Seminar', '3', 'KIRKWOOD HALL', ARRAY[]::TEXT[], 'Critical reading of autobiographies from diverse perspectives (race, class, gender, religion, disability, etc.) in order to develop empathy for the values and needs of diverse fashion consumers. Includes reflection/discussion about the practice of reading and writing autobiographies.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('SOAD-F 317', 'FASHION DESIGN RESEARCH', '12472', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–1:55 PM', 'KH 313', 'Jooyoung Shin', 3, NULL, 'Lecture', '3', 'KIRKWOOD HALL', ARRAY[]::TEXT[], 'Application of design research (historical, cultural, aesthetic, technological, market-driven, etc.) in the process of developing new fashion designs, drawing on both creative and critical thinking. Prior knowledge of materials, clothing construction methods, and tools for visual communication is essential. Studio class.', ARRAY[]::TEXT[], NULL),
    ('SOAD-F 317', 'FASHION DESIGN RESEARCH', '14378', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–5:05 PM', 'KH 313', 'Jooyoung Shin', 6, NULL, 'Lecture', '3', 'KIRKWOOD HALL', ARRAY[]::TEXT[], 'Application of design research (historical, cultural, aesthetic, technological, market-driven, etc.) in the process of developing new fashion designs, drawing on both creative and critical thinking. Prior knowledge of materials, clothing construction methods, and tools for visual communication is essential. Studio class.', ARRAY[]::TEXT[], NULL),
    ('SOAD-F 325', 'EXPERIMENTAL FASHION STUDIO: SHAPE AND FOUNDATION', '33337', 'Class Status', 'TuTh Tuesday, Thursday 8:00 AM–10:45 AM', 'KH 313', 'Jessica Quirk', 1, NULL, 'Lecture', '3', 'KIRKWOOD HALL', ARRAY[]::TEXT[], 'Fundamental principles of design for inner-shaping and foundation; manipulation of a variety of materials and techniques to produce original designs featuring complex super-structures. Studio class.', ARRAY[]::TEXT[], NULL),
    ('SOAD-F 340', 'HISTORY OF FASHION', '7664', 'Class Status', 'F Friday 11:00 AM–1:30 PM', 'KH 116', 'Heather Akou', 14, NULL, 'Lecture', '3', 'KIRKWOOD HALL', ARRAY[]::TEXT[], 'Dress in Western civilization relating to social, economic, political, and religious events in the eighteenth through twenty-first centuries; emphasis on the emergence and evolution of haute couture.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('SOAD-F 512', 'READINGS IN FASHION STUDIES', '33855', 'Closed', 'MW Monday, Wednesday 9:10 AM–11:55 AM', 'KH 318', 'Heather Akou', 2, NULL, 'Seminar', '3', 'KIRKWOOD HALL', ARRAY[]::TEXT[], 'Exploration of personal stories attached to dress and the body through books, museum archives, exhibits, films, and/or theatrical productions. Appropriate for graduate students as well as advanced undergraduates considering careers such as fashion curation, fashion media, fashion law, professional costuming, etc.', ARRAY[]::TEXT[], NULL),
    ('SOAD-G 901', 'ADVANCED RESEARCH', '4567', 'Class Status', NULL, NULL, 'Malcolm Smith', 5, NULL, 'Research', '6', NULL, ARRAY[]::TEXT[], 'Available to graduate students who have completed all course requirements for their doctorates, have passed doctoral qualifying examinations, and have the requisite number of degree credit hours, this course provides the advanced research student with a forum for sharing ideas and problems under the supervision of a senior researcher.', ARRAY[]::TEXT[], NULL),
    ('SOAD-M 109', 'APPAREL INDUSTRIES', '7715', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'BH 110', 'Elida Camille Behar', 18, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Introduction to the retail cycle related to the interdisciplinary study of and research in apparel and textiles. Examines social and economic theories underlying the fashion business, retail merchandising principles, consumer behavior, and contemporary retail issues.', ARRAY[]::TEXT[], NULL),
    ('SOAD-M 204', 'MANUFACTURING AND QUALITY ANALYSIS', '1011', 'Closed', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'KH 116', 'Susan White', 0, NULL, 'Lecture', '3', 'KIRKWOOD HALL', ARRAY[]::TEXT[], 'Focuses on the manufacturing and product development stage of the retail cycle. This stage comprises apparel merchandising history, technology, textiles, performance, value, and quality analysis.', ARRAY[]::TEXT[], NULL),
    ('SOAD-M 204', 'MANUFACTURING AND QUALITY ANALYSIS', '4218', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'KH 318', 'Susan White', 0, NULL, 'Lecture', '3', 'KIRKWOOD HALL', ARRAY[]::TEXT[], 'Focuses on the manufacturing and product development stage of the retail cycle. This stage comprises apparel merchandising history, technology, textiles, performance, value, and quality analysis.', ARRAY[]::TEXT[], NULL),
    ('SOAD-M 219', 'PROFESSIONAL DEVELOPMENT IN MERCHANDISING', '7714', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'KH 112', 'Susan White', 3, NULL, 'Lecture', '2', 'KIRKWOOD HALL', ARRAY[]::TEXT[], 'Professional techniques and competencies applicable to careers in the retail industry are explored while students participate in exercises to develop presentation skills and marketing themselves to, and in, a retail organization.', ARRAY['COLL (CASE) Career Readiness 2'], NULL),
    ('SOAD-M 255', 'DIGITAL MERCHANDISING', '33334', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'KH 112', 'Garim Lee', 0, NULL, 'Lecture', '3', 'KIRKWOOD HALL', ARRAY[]::TEXT[], 'Exploration and analysis of both customer behavior and business strategies in digital merchandising. Application of fundamental digital principles to the development of innovative digital merchandising strategies.', ARRAY[]::TEXT[], NULL),
    ('SOAD-M 255', 'DIGITAL MERCHANDISING', '33335', 'Closed', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'KH 116', 'Garim Lee', 0, NULL, 'Lecture', '3', 'KIRKWOOD HALL', ARRAY[]::TEXT[], 'Exploration and analysis of both customer behavior and business strategies in digital merchandising. Application of fundamental digital principles to the development of innovative digital merchandising strategies.', ARRAY[]::TEXT[], NULL),
    ('SOAD-M 308', 'BRAND MANAGEMENT AND ADVERTISING', '9621', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'KH 112', 'Elida Camille Behar', 0, NULL, 'Lecture', '3', 'KIRKWOOD HALL', ARRAY[]::TEXT[], 'Strategic marketing communication centered on building and maintaining brand equity, encompassing all stages of the retail cycle.', ARRAY[]::TEXT[], NULL),
    ('SOAD-M 309', 'STRATEGIES IN RETAIL PROMOTION', '7660', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'KH 112', 'Debra Pearson', 1, NULL, 'Lecture', '3', 'KIRKWOOD HALL', ARRAY[]::TEXT[], 'Application of design elements and principles to commercial display and development of creative visual merchandising techniques; various media explored.', ARRAY[]::TEXT[], NULL),
    ('SOAD-M 315', 'PRINCIPLES OF RETAIL MERCHANDISING', '1012', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'KH 116', 'Makaela Addington', 0, NULL, 'Lecture', '3', 'KIRKWOOD HALL', ARRAY[]::TEXT[], 'An examination of the contemporary retail environment as it relates to principles, such as the profit and loss analysis, retail math, markups, markdowns, and turnover. Comprehensive analysis and strategy development using retail merchandising principles are emphasized.', ARRAY[]::TEXT[], NULL),
    ('SOAD-M 315', 'PRINCIPLES OF RETAIL MERCHANDISING', '11737', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'KH 116', 'Makaela Addington', 0, NULL, 'Lecture', '3', 'KIRKWOOD HALL', ARRAY[]::TEXT[], 'An examination of the contemporary retail environment as it relates to principles, such as the profit and loss analysis, retail math, markups, markdowns, and turnover. Comprehensive analysis and strategy development using retail merchandising principles are emphasized.', ARRAY[]::TEXT[], NULL),
    ('SOAD-M 315', 'PRINCIPLES OF RETAIL MERCHANDISING', '12855', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'KH 116', 'William Kim', 0, NULL, 'Lecture', '3', 'KIRKWOOD HALL', ARRAY[]::TEXT[], 'An examination of the contemporary retail environment as it relates to principles, such as the profit and loss analysis, retail math, markups, markdowns, and turnover. Comprehensive analysis and strategy development using retail merchandising principles are emphasized.', ARRAY[]::TEXT[], NULL),
    ('SOAD-M 327', 'PRODUCT DEVELOPMENT', '8509', 'Closed', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'KH 116', 'Debra Pearson', 0, NULL, 'Lecture', '3', 'KIRKWOOD HALL', ARRAY[]::TEXT[], 'Functions and practices of product development; understanding and defining the customer; researching fashion trends from color and fabric to silhouette; identifying how and when to apply trends to targeted customers; practical application of executing concepts into finished products.', ARRAY[]::TEXT[], NULL),
    ('SOAD-M 350', 'OMNICHANNEL INNOVATION', '10160', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'KH 116', 'Minjeong Kim', 0, NULL, 'Lecture', '3', 'KIRKWOOD HALL', ARRAY[]::TEXT[], 'Application of Human-Centered Design (HCD, aka. design thinking) in omnichannel merchandising to develop innovative omnichannel solutions and improve consumer/human experience.', ARRAY[]::TEXT[], NULL),
    ('SOAD-M 385', 'CASE STUDIES IN MERCHANDISING', '10477', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'KH 112', 'Susan White', 2, NULL, 'Lecture', '2', 'KIRKWOOD HALL', ARRAY[]::TEXT[], 'Develops skills needed to solve issues presented in current merchandising case studies through creation of a plan for improved business performance.', ARRAY[]::TEXT[], NULL),
