    ('SOAD-S 300', 'DRAWING 2', '7991', 'Closed', 'MW Monday, Wednesday 3:55 PM–6:40 PM', 'FA 310', 'Bridget O''Brien', 0, NULL, 'Lecture', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'Intermediate course in drawing from the model and other sources. Emphasis on technical command of the media in conjunction with the development of a visual awareness. Continued problems in the articulation of space, scale, volume, value, and linear sensitivity.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('SOAD-S 300', 'DRAWING 2', '7992', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–1:55 PM', 'FA 310', 'Michael Reeves', 0, NULL, 'Lecture', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'Intermediate course in drawing from the model and other sources. Emphasis on technical command of the media in conjunction with the development of a visual awareness. Continued problems in the articulation of space, scale, volume, value, and linear sensitivity.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('SOAD-S 310', 'INTERACTIVE MULTIMEDIA', '7815', 'Closed', 'MW Monday, Wednesday 3:55 PM–6:40 PM', 'FA 215', 'Megan Young', 0, NULL, 'Lecture', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'Hands-on studio course exploring the intersection of art, technology, and human behavior by looking at the various bodies of knowledge that inform the interactive multimedia from storytelling, interaction design, installation, public intervention, and creative coding. This project-based course covers conceptually-oriented digital art practices spanning audio & video production, coding with HTML5, CSS, JavaScript, animation in Adobe After Effects, and physical computing with Arduino.', ARRAY[]::TEXT[], NULL),
    ('SOAD-S 311', 'VIDEO ART', '7816', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–1:55 PM', 'FA 215', 'clay scofield', 0, NULL, 'Lecture', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'Exploration of the medium of video as an aesthetic expression. Time and sound are elements incorporated into visual composition''s traditional concerns. Emphasis on technical command of video camera and digital editing procedures in conjunction with development of a visual sensitivity. Readings and a research project are required.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('SOAD-S 313', '3D COMPUTER GRAPHICS', '1753', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–5:05 PM', 'FA 215', 'Patrick Stefaniak', 3, NULL, 'Laboratory', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'Hands-on studio course exploring the technical development of three-dimensional computer graphics for state-of-the-art display systems. Includes investigation of user-interface design, creation of 3D graphical environments, and exploration of the parallel drives toward content creation and visual aesthetics.', ARRAY[]::TEXT[], NULL),
    ('SOAD-S 320', 'FIBERS II', '7989', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–5:05 PM', 'FA 230', 'Rowland Ricketts', 0, NULL, 'Lecture', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'Expands students'' technical, creative, and critical abilities when working with fibers and textile-related materials, processes, and concepts. Rotating semester topics include advanced dyeing, repeat-pattern design and screenprinting, weaving, soft sculpture, performance, wearables, and installation.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('SOAD-S 330', 'PAINTING 2', '7998', 'Closed', 'MW Monday, Wednesday 12:45 PM–3:30 PM', 'FA 318', 'Alison Cofrancesco', 0, NULL, 'Lecture', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'Intermediate course in painting from the model and other sources. Emphasis on technical command and understanding of the components of painting space, color, volume, value, and scale. Media: oil or acrylics.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('SOAD-S 330', 'PAINTING 2', '7999', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–5:05 PM', 'FA 318', 'Amanda Smith', 0, NULL, 'Lecture', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'Intermediate course in painting from the model and other sources. Emphasis on technical command and understanding of the components of painting space, color, volume, value, and scale. Media: oil or acrylics.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('SOAD-S 341', 'PRINTMAKING II INTAGLIO', '14405', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–1:55 PM', 'AZ 124', 'Tracy Templeton', 0, NULL, 'Laboratory', '3', 'STUDIO ARTS ANNEX', ARRAY[]::TEXT[], 'Advanced study with focus on intaglio. Emphasis on drawn, painterly and photographic Intaglio processes.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('SOAD-S 343', 'PRINTMAKING II LITHOGRAPHY', '32796', 'Class Status', 'MW Monday, Wednesday 12:45 PM–3:30 PM', 'AZ 125', 'Jennifer Johnson', 5, NULL, 'Studio', '3', 'STUDIO ARTS ANNEX', ARRAY[]::TEXT[], 'Advanced study with focus on lithography. Emphasis on drawn and photographic lithography processes.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('SOAD-S 351', 'GRAPHIC DESIGN II TYPOGRAPHY', '7819', 'Class Status', 'MW Monday, Wednesday 3:55 PM–6:40 PM', 'FA 137', 'Javier Viramontes', 7, NULL, 'Lecture', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'Studies in visual communication with an emphasis on typography, including measurement and structure, detail and refinement, hierarchy and legibility, tools, and application to various media in digital and print formats. An introduction to type history, aesthetics and analysis are also considered.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('SOAD-S 351', 'GRAPHIC DESIGN II TYPOGRAPHY', '8430', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–5:05 PM', 'FA 137', 'Ryan Irvin', 3, NULL, 'Lecture', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'Studies in visual communication with an emphasis on typography, including measurement and structure, detail and refinement, hierarchy and legibility, tools, and application to various media in digital and print formats. An introduction to type history, aesthetics and analysis are also considered.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('SOAD-S 360', 'CERAMICS 2', '8006', 'Closed', 'MW Monday, Wednesday 9:10 AM–11:55 AM', 'FA 152', 'Ellen Kleckner', 0, NULL, 'Lecture', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'Intermediate level practice in ceramics. Instruction through lecture, demonstration, and group critiques. Topics vary per semester and instructor; including throwing, hand building, mold making, casting, kiln building, ceramics + color, and alternative firing.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('SOAD-S 360', 'CERAMICS 2', '8007', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–5:05 PM', 'FA 152', 'Malcolm Smith', 0, NULL, 'Lecture', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'Intermediate level practice in ceramics. Instruction through lecture, demonstration, and group critiques. Topics vary per semester and instructor; including throwing, hand building, mold making, casting, kiln building, ceramics + color, and alternative firing.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('SOAD-S 370', 'SCULPTURE 2', '14408', 'Closed', 'MW Monday, Wednesday 12:45 PM–3:30 PM', 'AZ A107', 'Michael Calway-Fagen', 0, NULL, 'Laboratory', '3', 'STUDIO ARTS ANNEX', ARRAY[]::TEXT[], 'Development of skills in both traditional and contemporary sculpture methodology. Rotating semester topics may include figurative sculpture, carving, casting, steel/wood construction, computer-aided machining and rapid prototyping, installation art, performance art and public art. Emphasis on the exploration of ideas through the sculptural form and knowledge of materials and historical traditions.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('SOAD-S 380', 'METALSMITHING AND JEWELRY DESIGN II', '11435', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–1:55 PM', 'FA 210', 'Angela Caldwell', 8, NULL, 'Lecture', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'Extensive designing and model making for exploring forms and ideas in metal and mixed media, either as jewelry or hollowware objects such as flatware, tea strainers/infusers, boxes, or small-scale sculpture. Focuses on the techniques of angle raising, forging, stone setting, jewelry mechanisms, and hinge making.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('SOAD-S 390', 'PHOTOGRAPHY II', '8018', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–5:05 PM', 'FA 023', 'Osamu Nakagawa', 0, NULL, 'Lecture', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'Practice of digital color or chemical photography: camera work, darkroom practices, appreciation of photographs, and experience in expressive use of the medium.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('SOAD-S 400', 'DRAWING 3', '7993', 'Closed', 'MW Monday, Wednesday 3:55 PM–6:40 PM', 'FA 310', 'Bridget O''Brien', 0, NULL, 'Lecture', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'Advanced drawing. Continuation of SOAD-S 300 or FINA-S 301.', ARRAY[]::TEXT[], NULL),
    ('SOAD-S 400', 'DRAWING 3', '7994', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–1:55 PM', 'FA 310', 'Michael Reeves', 0, NULL, 'Lecture', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'Advanced drawing. Continuation of SOAD-S 300 or FINA-S 301.', ARRAY[]::TEXT[], NULL),
    ('SOAD-S 410', 'ADVANCED MULTIMEDIA', '7987', 'Closed', 'MW Monday, Wednesday 3:55 PM–6:40 PM', 'FA 215', 'Megan Young', 0, NULL, 'Lecture', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'Hands-on studio course exploring the intersection of art, technology, and human behavior by looking at the various bodies of knowledge that inform the interactive multimedia from storytelling, interaction design, installation, public intervention, and creative coding. Covers conceptually-oriented digital art practices spanning audio and video production, coding with HTML5, CSS, JavaScript, animation in Adobe After Effects, and physical computing with Arduino. Dialogue of timely issues through readings, screenings, websites, and gallery visits. Emphasis on a more self-guided conceptual practice.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('SOAD-S 411', 'DIGITAL VIDEO', '7356', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–1:55 PM', 'FA 215', 'clay scofield', 0, NULL, 'Lecture', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'Advanced study of video''s potential in contemporary fine art practice. Students will create a new visual vocabulary using the latest technology including high-definition video systems and interactive DVD authoring. Covers special effects and animation programs that allow artists to further explore the aesthetics of time-based media.', ARRAY[]::TEXT[], NULL),
    ('SOAD-S 412', 'BFA DIGITAL ART', '7986', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–5:05 PM', 'FA 235', 'Megan Young', 7, NULL, 'Lecture', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'Directed, advanced study and production of a body of work leading to B.F.A. exhibition. Students meet independently with instructor and in group critiques to maintain a dialogue and provide technical advice.', ARRAY[]::TEXT[], NULL),
    ('SOAD-S 413', 'COMPUTER GRAPHICAL ENVIRONMENTS', '1754', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–5:05 PM', 'FA 215', 'Patrick Stefaniak', 3, NULL, 'Laboratory', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'Further develops skills in 3D computer graphics, virtual reality, and real-time rendered displays and explores techniques involved in the creation of 3D models, texture mapping, lighting, environment design, rendering for virtual reality, and interaction. Readings, videos, gallery visits, websites, etc., encourage discussion of current issues in the field.', ARRAY[]::TEXT[], NULL),
    ('SOAD-S 419', 'BFA DIGITAL ART SEMINAR', '12510', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'VD 200', 'Jonathan Gamblin, Alexander Landerman', 4, NULL, 'Lecture', '3', 'ESKENAZI SCHL / MIES VAN DER R', ARRAY[]::TEXT[], 'Taught on a rotating basis by Digital Art/Studio Art faculty. Includes critiques of student work, discussion of special topics, assigned readings, multimedia lectures, visiting artist lectures, and special research projects intended to develop a compelling personal narrative and professional relationships to aid students in building their careers.', ARRAY['COLL (CASE) Career Readiness 2'], NULL),
    ('SOAD-S 419', 'BFA DIGITAL ART SEMINAR', '12511', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'VD 200', 'Angela Caldwell, Amanda Smith', 4, NULL, 'Lecture', '3', 'ESKENAZI SCHL / MIES VAN DER R', ARRAY[]::TEXT[], 'Taught on a rotating basis by Digital Art/Studio Art faculty. Includes critiques of student work, discussion of special topics, assigned readings, multimedia lectures, visiting artist lectures, and special research projects intended to develop a compelling personal narrative and professional relationships to aid students in building their careers.', ARRAY['COLL (CASE) Career Readiness 2'], NULL),
    ('SOAD-S 420', 'FIBERS III', '5159', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–5:05 PM', 'FA 230', 'Rowland Ricketts', 0, NULL, 'Lecture', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'A continued exploration of fiber and textile-related materials, processes, and concepts with an emphasis on conceptual development, independent investigation and production.', ARRAY[]::TEXT[], NULL),
    ('SOAD-S 422', 'BFA FIBERS', '3277', 'Class Status', 'MW Monday, Wednesday 12:45 PM–3:30 PM', 'FA 230', 'Rowland Ricketts', 3, NULL, 'Lecture', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'Intensive study in fibers and textile-related materials, processes, and concepts through the production of a body of work reflecting the student''s individual interests. Regular individual meetings and group critiques are planned to foster dialogue and provide additional support.', ARRAY[]::TEXT[], NULL),
