    ('SOAD-S 460', 'CERAMICS 3', '8008', 'Closed', 'MW Monday, Wednesday 9:10 AM–11:55 AM', 'FA 152', 'Ellen Kleckner', 0, NULL, 'Lecture', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'Further practice in advanced ceramic techniques. Instruction through lectures, demonstrations, and critiques. Topics vary by instructor and semester.', ARRAY[]::TEXT[], NULL),
