    ('SOAD-S 468', 'HISTORY OF CERAMICS', '30464', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'AZ 130', 'Timothy Mather', 6, NULL, 'Lecture', '3', 'STUDIO ARTS ANNEX', ARRAY[]::TEXT[], 'Emphasis on the historical development of pottery in individual cultures, as well as how one culture''s pottery has influenced another''s.', ARRAY[]::TEXT[], NULL),
