    ('SOAD-S 479', 'BFA SCULPTURE SEMINAR', '12541', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'VD 200', 'Jonathan Gamblin, Alexander Landerman', 4, NULL, 'Lecture', '3', 'ESKENAZI SCHL / MIES VAN DER R', ARRAY[]::TEXT[], 'Taught on a rotating basis by Sculpture/Studio Art faculty. Includes critiques of student work, discussion of special topics, assigned readings, multimedia lectures, visiting artist lectures, and special research projects intended to develop a compelling personal narrative and professional relationships to aid students in building their careers.', ARRAY['COLL (CASE) Career Readiness 2'], NULL),
    ('SOAD-S 479', 'BFA SCULPTURE SEMINAR', '12542', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'VD 200', 'Angela Caldwell, Amanda Smith', 4, NULL, 'Lecture', '3', 'ESKENAZI SCHL / MIES VAN DER R', ARRAY[]::TEXT[], 'Taught on a rotating basis by Sculpture/Studio Art faculty. Includes critiques of student work, discussion of special topics, assigned readings, multimedia lectures, visiting artist lectures, and special research projects intended to develop a compelling personal narrative and professional relationships to aid students in building their careers.', ARRAY['COLL (CASE) Career Readiness 2'], NULL),
    ('SOAD-S 480', 'METALSMITHING AND JEWELRY DESIGN III', '8013', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–1:55 PM', 'FA 210', 'Angela Caldwell', 8, NULL, 'Lecture', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'A continued exploration of metalsmithing and jewelry design materials, processes, and concepts with an emphasis on independent investigation and production. Guidance toward developing a personal direction of creative expression, artistic aesthetic, and art philosophy. Rotating semester topics include; large-scale vessels from metal sheet fabrication, large-scale soldering, die forming, advanced jewelry mechanisms, chain making, chasing and repoussé, enameling, and working with alternative materials.', ARRAY[]::TEXT[], NULL),
    ('SOAD-S 482', 'BFA METALSMITHING AND JEWELRY DESIGN', '1751', 'Class Status', 'MW Monday, Wednesday 12:45 PM–3:30 PM', 'FA 210', 'Nicole Jacquard', 9, NULL, 'Laboratory', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'Mentor-directed, independent study in jewelry and metalsmithing leading to the development of a professional portfolio and a BFA thesis exhibition reflecting the individual''s interests.', ARRAY[]::TEXT[], NULL),
    ('SOAD-S 489', 'BFA METALSMITHING AND JEWELRY DESIGN SEMINAR', '12546', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'VD 200', 'Jonathan Gamblin, Alexander Landerman', 4, NULL, 'Lecture', '3', 'ESKENAZI SCHL / MIES VAN DER R', ARRAY[]::TEXT[], 'Taught on a rotating basis by Metals/Studio Art faculty. Includes critiques of student work, discussion of special topics, assigned readings, multimedia lectures, visiting artist lectures, and special research projects intended to develop a compelling personal narrative and professional relationships to aid students in building their careers.', ARRAY['COLL (CASE) Career Readiness 2'], NULL),
    ('SOAD-S 489', 'BFA METALSMITHING AND JEWELRY DESIGN SEMINAR', '12547', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'VD 200', 'Angela Caldwell, Amanda Smith', 4, NULL, 'Lecture', '3', 'ESKENAZI SCHL / MIES VAN DER R', ARRAY[]::TEXT[], 'Taught on a rotating basis by Metals/Studio Art faculty. Includes critiques of student work, discussion of special topics, assigned readings, multimedia lectures, visiting artist lectures, and special research projects intended to develop a compelling personal narrative and professional relationships to aid students in building their careers.', ARRAY['COLL (CASE) Career Readiness 2'], NULL),
    ('SOAD-S 490', 'PHOTOGRAPHY III', '6297', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–1:55 PM', 'FA 023', 'Osamu Nakagawa', 0, NULL, 'Lecture', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'Emphasizes advanced conceptual and technical development in digital and traditional photographic media and the expansion of creative possibilities. Topics vary. May include such topics as alternative processes, advanced Photoshop, documentary and large format photography, photographic theory, installation art, and black and white darkroom practice.', ARRAY[]::TEXT[], NULL),
    ('SOAD-S 492', 'BFA PHOTOGRAPHY', '8633', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–5:05 PM', 'FA 020', 'David Ondrik', 5, NULL, 'Lecture', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'Directed advanced study and production of a body of work leading to an exhibition. Students meet independently with instructor and in groups for critiques and lectures to maintain a dialogue with contemporary issues and to provide technical advice.', ARRAY[]::TEXT[], NULL),
    ('SOAD-S 499', 'BFA PHOTOGRAPHY SEMINAR', '12552', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'VD 200', 'Jonathan Gamblin, Alexander Landerman', 4, NULL, 'Lecture', '3', 'ESKENAZI SCHL / MIES VAN DER R', ARRAY[]::TEXT[], 'Taught on a rotating basis by Photography/Studio Art faculty. Includes critiques of student work, discussion of special topics, assigned readings, multimedia lectures, visiting artist lectures, and special research projects intended to develop a compelling personal narrative and professional relationships to aid students in building their careers.', ARRAY['COLL (CASE) Career Readiness 2'], NULL),
    ('SOAD-S 499', 'BFA PHOTOGRAPHY SEMINAR', '12553', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'VD 200', 'Angela Caldwell, Amanda Smith', 4, NULL, 'Lecture', '3', 'ESKENAZI SCHL / MIES VAN DER R', ARRAY[]::TEXT[], 'Taught on a rotating basis by Photography/Studio Art faculty. Includes critiques of student work, discussion of special topics, assigned readings, multimedia lectures, visiting artist lectures, and special research projects intended to develop a compelling personal narrative and professional relationships to aid students in building their careers.', ARRAY['COLL (CASE) Career Readiness 2'], NULL),
    ('SOAD-S 500', 'GRADUATE TOPICS IN DRAWING', '8210', 'Closed', 'MW Monday, Wednesday 3:55 PM–6:40 PM', 'FA 310', 'Bridget O''Brien', 0, NULL, 'Laboratory', '1–3', 'FINE ARTS', ARRAY[]::TEXT[], 'Advanced drawing for graduate students.', ARRAY[]::TEXT[], NULL),
    ('SOAD-S 500', 'GRADUATE TOPICS IN DRAWING', '8211', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–1:55 PM', 'FA 310', 'Michael Reeves', 0, NULL, 'Laboratory', '1–3', 'FINE ARTS', ARRAY[]::TEXT[], 'Advanced drawing for graduate students.', ARRAY[]::TEXT[], NULL),
    ('SOAD-S 509', 'MFA DRAWING SEMINAR', '8212', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'AZ 130', 'Carissa Carman', 4, NULL, 'Seminar', '3', 'STUDIO ARTS ANNEX', ARRAY[]::TEXT[], 'General seminar on source drawing. Sessions from the model will be made available. Examples of drawing from the history of art are used in reference to each student''s particular stylistic bias. Stylistic development as well as composition are stressed along with a concentration on craftsmanship.', ARRAY[]::TEXT[], NULL),
    ('SOAD-S 509', 'MFA DRAWING SEMINAR', '12523', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'AZ 130', 'Caleb Weintraub', 3, NULL, 'Seminar', '3', 'STUDIO ARTS ANNEX', ARRAY[]::TEXT[], 'General seminar on source drawing. Sessions from the model will be made available. Examples of drawing from the history of art are used in reference to each student''s particular stylistic bias. Stylistic development as well as composition are stressed along with a concentration on craftsmanship.', ARRAY[]::TEXT[], NULL),
    ('SOAD-S 509', 'MFA DRAWING SEMINAR', '12524', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'FA 230', 'Malcolm Smith', 6, NULL, 'Seminar', '3', 'STUDIO ARTS ANNEX', ARRAY[]::TEXT[], 'General seminar on source drawing. Sessions from the model will be made available. Examples of drawing from the history of art are used in reference to each student''s particular stylistic bias. Stylistic development as well as composition are stressed along with a concentration on craftsmanship.', ARRAY[]::TEXT[], NULL),
    ('SOAD-S 510', 'GRADUATE TOPICS IN DIGITAL ART', '8215', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–5:05 PM', 'FA 215', 'Patrick Stefaniak', 3, NULL, 'Lecture', '1–3', 'FINE ARTS', ARRAY[]::TEXT[], 'Advanced opportunity for students to investigate the computer as an interactive tool in the process of art making while examining aesthetics and processes of major artists working in this field. Provides the opportunity for exploration of the computer''s potential use in the art work of each class member.', ARRAY[]::TEXT[], NULL),
    ('SOAD-S 510', 'GRADUATE TOPICS IN DIGITAL ART', '8213', 'Closed', 'MW Monday, Wednesday 3:55 PM–6:40 PM', 'FA 215', 'Megan Young', 0, NULL, 'Lecture', '1–3', 'FINE ARTS', ARRAY[]::TEXT[], 'Advanced opportunity for students to investigate the computer as an interactive tool in the process of art making while examining aesthetics and processes of major artists working in this field. Provides the opportunity for exploration of the computer''s potential use in the art work of each class member.', ARRAY[]::TEXT[], NULL),
    ('SOAD-S 510', 'GRADUATE TOPICS IN DIGITAL ART', '8214', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–1:55 PM', 'FA 215', 'clay scofield', 0, NULL, 'Lecture', '1–3', 'FINE ARTS', ARRAY[]::TEXT[], 'Advanced opportunity for students to investigate the computer as an interactive tool in the process of art making while examining aesthetics and processes of major artists working in this field. Provides the opportunity for exploration of the computer''s potential use in the art work of each class member.', ARRAY[]::TEXT[], NULL),
    ('SOAD-S 511', 'GRADUATE DIGITAL ART', '8216', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–5:05 PM', 'FA 235', 'Megan Young', 2, NULL, 'Lecture', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'Through advanced studio projects in digital art, the student will create a body of work involving experimentation with technology incorporating installation, multimedia, networks, virtual environments, and/or portable media. Topics of relevance to contemporary digital art will be considered, such as interaction, time-based media, location and virtuality.', ARRAY[]::TEXT[], NULL),
    ('SOAD-S 519', 'MFA DIGITAL ART SEMINAR', '8217', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'AZ 130', 'Carissa Carman', 4, NULL, 'Seminar', '3', 'STUDIO ARTS ANNEX', ARRAY[]::TEXT[], 'Investigates the relationship between art, aesthetics, and technology. Topics can include virtual environments, screen-media, sound art, time-based media, networked art, and locative media, as well as related history, criticism and theory. Coursework includes readings, discussions and research-based projects, papers or presentations.', ARRAY[]::TEXT[], NULL),
    ('SOAD-S 519', 'MFA DIGITAL ART SEMINAR', '12513', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'AZ 130', 'Caleb Weintraub', 3, NULL, 'Seminar', '3', 'STUDIO ARTS ANNEX', ARRAY[]::TEXT[], 'Investigates the relationship between art, aesthetics, and technology. Topics can include virtual environments, screen-media, sound art, time-based media, networked art, and locative media, as well as related history, criticism and theory. Coursework includes readings, discussions and research-based projects, papers or presentations.', ARRAY[]::TEXT[], NULL),
    ('SOAD-S 519', 'MFA DIGITAL ART SEMINAR', '12514', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'FA 230', 'Malcolm Smith', 6, NULL, 'Seminar', '3', 'STUDIO ARTS ANNEX', ARRAY[]::TEXT[], 'Investigates the relationship between art, aesthetics, and technology. Topics can include virtual environments, screen-media, sound art, time-based media, networked art, and locative media, as well as related history, criticism and theory. Coursework includes readings, discussions and research-based projects, papers or presentations.', ARRAY[]::TEXT[], NULL),
