    ('SOAD-S 549', 'MFA PRINTMAKING SEMINAR', '8224', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'AZ 130', 'Carissa Carman', 4, NULL, 'Lecture', '3', 'STUDIO ARTS ANNEX', ARRAY[]::TEXT[], 'Deals with both theoretical and practical issues in contemporary art. Discussions will be based on selected readings, including relevant suggestions from the participants. Students will make presentations on the influences and development of their work as well as collaborative research.', ARRAY[]::TEXT[], NULL),
