    ('SOAD-S 549', 'MFA PRINTMAKING SEMINAR', '12529', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'FA 230', 'Malcolm Smith', 6, NULL, 'Lecture', '3', 'STUDIO ARTS ANNEX', ARRAY[]::TEXT[], 'Deals with both theoretical and practical issues in contemporary art. Discussions will be based on selected readings, including relevant suggestions from the participants. Students will make presentations on the influences and development of their work as well as collaborative research.', ARRAY[]::TEXT[], NULL),
    ('SOAD-S 550', 'GRADUATE TOPICS IN GRAPHIC DESIGN', '14400', 'Class Status', 'MW Monday, Wednesday 9:10 AM–11:55 AM', 'FA 137', 'Carrie Hott', 9, NULL, 'Laboratory', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'Professional problem solving in graphic design. Using a variety of mediums to communicate messages, students apply processes from printing to multimedia as appropriate for directed projects.', ARRAY[]::TEXT[], NULL),
    ('SOAD-S 550', 'GRADUATE TOPICS IN GRAPHIC DESIGN', '14399', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–1:55 PM', 'FA 137', 'Alexander Landerman', 0, NULL, 'Laboratory', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'Professional problem solving in graphic design. Using a variety of mediums to communicate messages, students apply processes from printing to multimedia as appropriate for directed projects.', ARRAY[]::TEXT[], NULL),
    ('SOAD-S 551', 'GRADUATE GRAPHIC DESIGN', '8260', 'Class Status', 'MW Monday, Wednesday 12:45 PM–3:30 PM', 'FA 240', 'Alexander Landerman, Carrie Hott', 3, NULL, 'Lecture', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'Graphic design as an integral element of all visual communication media. Self-defined and assigned study to assure as wide as possible exposure to the problem-solving process.', ARRAY[]::TEXT[], NULL),
    ('SOAD-S 559', 'MFA GRAPHIC DESIGN SEMINAR', '8225', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'AZ 130', 'Carissa Carman', 4, NULL, 'Lecture', '3', 'STUDIO ARTS ANNEX', ARRAY[]::TEXT[], 'Provides background on major graphic design movements, the design of the alphabet and type styles, the use of tools (printing press, wood cut, engraving, camera, airbrush, computer). Social and political forces such as industrial development and nationalism will be considered. Writings of theorists and historians will be reviewed.', ARRAY[]::TEXT[], NULL),
    ('SOAD-S 559', 'MFA GRAPHIC DESIGN SEMINAR', '12534', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'AZ 130', 'Caleb Weintraub', 3, NULL, 'Lecture', '3', 'STUDIO ARTS ANNEX', ARRAY[]::TEXT[], 'Provides background on major graphic design movements, the design of the alphabet and type styles, the use of tools (printing press, wood cut, engraving, camera, airbrush, computer). Social and political forces such as industrial development and nationalism will be considered. Writings of theorists and historians will be reviewed.', ARRAY[]::TEXT[], NULL),
    ('SOAD-S 559', 'MFA GRAPHIC DESIGN SEMINAR', '12535', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'FA 230', 'Malcolm Smith', 6, NULL, 'Lecture', '3', 'STUDIO ARTS ANNEX', ARRAY[]::TEXT[], 'Provides background on major graphic design movements, the design of the alphabet and type styles, the use of tools (printing press, wood cut, engraving, camera, airbrush, computer). Social and political forces such as industrial development and nationalism will be considered. Writings of theorists and historians will be reviewed.', ARRAY[]::TEXT[], NULL),
    ('SOAD-S 560', 'GRADUATE TOPICS IN CERAMICS', '8263', 'Class Status', 'MW Monday, Wednesday 9:10 AM–11:55 AM', 'FA 152', 'Ellen Kleckner', 4, NULL, 'Laboratory', '1–3', 'FINE ARTS', ARRAY[]::TEXT[], 'Further practice in advanced ceramic techniques. Instruction through lectures, demonstrations, and critiques. Topics vary by instructor and semester.', ARRAY[]::TEXT[], NULL),
    ('SOAD-S 560', 'GRADUATE TOPICS IN CERAMICS', '8264', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–5:05 PM', 'FA 152', 'Malcolm Smith', 0, NULL, 'Laboratory', '1–3', 'FINE ARTS', ARRAY[]::TEXT[], 'Further practice in advanced ceramic techniques. Instruction through lectures, demonstrations, and critiques. Topics vary by instructor and semester.', ARRAY[]::TEXT[], NULL),
    ('SOAD-S 561', 'GRADUATE CERAMICS', '8261', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–1:55 PM', 'AZ A024', 'Jonathan Gamblin', 7, NULL, 'Laboratory', '3', 'STUDIO ARTS ANNEX', ARRAY[]::TEXT[], 'Studio techniques: advanced practice in the use of clay for expression or functional ceramics purposes. Theory: clay and body compositions glaze; materials, oxides, glaze compositions and calculation, firing procedures.', ARRAY[]::TEXT[], NULL),
    ('SOAD-S 568', 'GRADUATE HISTORY OF CERAMICS', '30466', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'AZ 130', 'Timothy Mather', 6, NULL, 'Lecture', '3', 'STUDIO ARTS ANNEX', ARRAY[]::TEXT[], 'Emphasis on the historical development of pottery in individual cultures, as well as how one culture''s pottery has influenced another''s.', ARRAY[]::TEXT[], NULL),
