    ('SOAD-S 589', 'MFA METALSMITHING AND JEWELRY DESIGN SEMINAR', '12550', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'FA 230', 'Malcolm Smith', 6, NULL, 'Lecture', '3', 'STUDIO ARTS ANNEX', ARRAY[]::TEXT[], 'Primarily for students enrolled in the Metals MFA program. Weekly meetings include; critiques of individual research, oral and written study, and special projects.', ARRAY[]::TEXT[], NULL),
    ('SOAD-S 590', 'GRADUATE TOPICS IN PHOTOGRAPHY', '8265', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–1:55 PM', 'FA 023', 'Osamu Nakagawa', 0, NULL, 'Studio', '1–3', 'FINE ARTS', ARRAY[]::TEXT[], 'Emphasizes advanced conceptual and technical development in digital and traditional photographic media and the expansion of creative possibilities. Topics vary. May include topics as alternative processes, advanced Photoshop, documentary, artist book making, photographic theory, installation art, and darkroom practice.', ARRAY[]::TEXT[], NULL),
    ('SOAD-S 591', 'GRADUATE PHOTOGRAPHY', '8241', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–5:05 PM', 'FA 020', 'David Ondrik', 5, NULL, 'Laboratory', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'Intensive directed study in photography. For students admitted to the M.F.A. program in photography.', ARRAY[]::TEXT[], NULL),
    ('SOAD-S 599', 'MFA PHOTOGRAPHY SEMINAR', '8242', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'AZ 130', 'Carissa Carman', 4, NULL, 'Lecture', '3', 'STUDIO ARTS ANNEX', ARRAY[]::TEXT[], 'Primarily for graduate students in photography. Oral and written study of both theoretical and practical issues in the history, criticism and theory of photography. Discussions will be based on selected readings, including relevant suggestions from the participants.', ARRAY[]::TEXT[], NULL),
    ('SOAD-S 599', 'MFA PHOTOGRAPHY SEMINAR', '12555', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'AZ 130', 'Caleb Weintraub', 3, NULL, 'Lecture', '3', 'STUDIO ARTS ANNEX', ARRAY[]::TEXT[], 'Primarily for graduate students in photography. Oral and written study of both theoretical and practical issues in the history, criticism and theory of photography. Discussions will be based on selected readings, including relevant suggestions from the participants.', ARRAY[]::TEXT[], NULL),
    ('SOAD-S 599', 'MFA PHOTOGRAPHY SEMINAR', '12556', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'FA 230', 'Malcolm Smith', 6, NULL, 'Lecture', '3', 'STUDIO ARTS ANNEX', ARRAY[]::TEXT[], 'Primarily for graduate students in photography. Oral and written study of both theoretical and practical issues in the history, criticism and theory of photography. Discussions will be based on selected readings, including relevant suggestions from the participants.', ARRAY[]::TEXT[], NULL),
    ('SOAD-S 600', 'FABRICATION TOOLS AND TECHNOLOGY', '33933', 'Class Status', 'MW Monday, Wednesday 3:55 PM–6:40 PM', 'CO 100', 'Justin Bailey', 2, NULL, 'Studio', '3', 'ESKENAZI WOOD AND METAL SHOP', ARRAY[]::TEXT[], 'A graduate level course within the Eskenazi School of Art, Architecture and Design, intended for those pursuing an MFA in Studio Art. This course emphasizes in-depth study of materials, tools, and technologies used in the creation of works of art, craft, and design, as well as their installation and exhibition.', ARRAY[]::TEXT[], NULL),
    ('SOAD-S 710', 'DIGITAL ART ADVANCED STUDIO PROJECTS', '8227', 'Class Status', NULL, NULL, 'Megan Young', 10, NULL, 'Lecture', '1–6', NULL, ARRAY[]::TEXT[], 'Independent study in computer art. Faculty and student consultations will determine the project and credit hours to be assigned.', ARRAY[]::TEXT[], NULL),
    ('SOAD-S 720', 'FIBERS ADVANCED STUDIO PROJECTS', '8228', 'Class Status', NULL, NULL, 'Rowland Ricketts', 9, NULL, 'Lecture', '1–6', NULL, ARRAY[]::TEXT[], 'Directed graduate-level independent study in Fibers. Requires authorization of the instructor.', ARRAY[]::TEXT[], NULL),
