    ('SOAD-S 740', 'PRINTMAKING ADVANCED STUDIO PROJECTS', '8230', 'Class Status', NULL, NULL, 'Tracy Templeton', 6, NULL, 'Lecture', '1–6', NULL, ARRAY[]::TEXT[], 'Directed graduate-level independent study in printmaking.', ARRAY[]::TEXT[], NULL),
