    ('SOAD-S 780', 'METALSMITHING AND JEWELRY DESIGN ADVANCED STUDIO PROJECTS', '8233', 'Class Status', NULL, NULL, 'Nicole Jacquard', 9, NULL, 'Lecture', '1–6', NULL, ARRAY[]::TEXT[], 'Directed graduate-level independent study in metalsmithing and jewelry design. Requires authorization of the instructor.', ARRAY[]::TEXT[], NULL),
