    ('SOAD-U 400', 'BFA FINAL REVIEW', '7831', 'Class Status', NULL, NULL, 'Martha MacLeish', 10, NULL, 'Independent Study', '0', NULL, ARRAY[]::TEXT[], 'Final portfolio review for B.F.A. program.', ARRAY[]::TEXT[], NULL),
    ('SOAD-U 401', 'SPECIAL TOPICS IN STUDIO ART', '34062', 'Class Status', 'TuTh Tuesday, Thursday 3:35 PM–4:50 PM', 'SY 137', 'Douglas Hofstadter', 4, NULL, 'Lecture', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'Special topics in studio art not ordinarily covered in other departmental courses.', ARRAY[]::TEXT[], NULL),
    ('SOAD-U 402', 'TECHNICAL RESOURCES IN STUDIO ART', '1755', 'Class Status', 'F Friday 9:10 AM–12:10 PM', 'CO 100', 'Daniel Woerner', 4, NULL, 'Laboratory', '1', 'ESKENAZI WOOD AND METAL SHOP', ARRAY[]::TEXT[], 'Special aspects of studio training in the various disciplines focusing on technical and safety issues of equipment use and/or chemical substances. May include advance aspects of technologies in studio areas and preparation for use of facilities in independent studio projects.', ARRAY[]::TEXT[], NULL),
    ('SOAD-U 402', 'TECHNICAL RESOURCES IN STUDIO ART', '1756', 'Closed', 'F Friday 9:10 AM–12:10 PM', 'CO 100', 'Daniel Woerner', 0, NULL, 'Laboratory', '1', 'ESKENAZI WOOD AND METAL SHOP', ARRAY[]::TEXT[], 'Special aspects of studio training in the various disciplines focusing on technical and safety issues of equipment use and/or chemical substances. May include advance aspects of technologies in studio areas and preparation for use of facilities in independent studio projects.', ARRAY[]::TEXT[], NULL),
    ('SOAD-U 450', 'INDEPENDENT STUDIO PROJECTS', '8038', 'Class Status', NULL, NULL, 'Martha MacLeish', 4, NULL, 'Lecture', '1–3', NULL, ARRAY[]::TEXT[], 'Individual studio projects under guidance of faculty member or committee.', ARRAY[]::TEXT[], NULL),
    ('SOAD-U 501', 'SPECIAL TOPICS IN STUDIO ART', '34063', 'Class Status', 'TuTh Tuesday, Thursday 3:35 PM–4:50 PM', 'SY 137', 'Douglas Hofstadter', 4, NULL, 'Lecture', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'Selected topics in studio art not ordinarily covered in other departmental courses.', ARRAY[]::TEXT[], NULL),
    ('SOAD-U 695', 'ART + DESIGN FUTURE FACULTY SEMINAR', '11795', 'Class Status', 'MW Monday, Wednesday 5:15 PM–6:30 PM', 'VD 200', 'Martha MacLeish', 14, NULL, 'Lecture', '3', 'ESKENAZI SCHL / MIES VAN DER R', ARRAY[]::TEXT[], 'This course is required for all associate instructors teaching for the first time in the Eskenazi School of Art, Architecture + Design. Topics include effective communication of ideas about art & design; health and safety regulations relevant to studio courses; grading; critiquing; and a number of course-specific teaching issues.', ARRAY[]::TEXT[], NULL),
    ('SOAD-U 700', 'ADVANCED STUDIO PROJECTS', '11423', 'Class Status', 'MTuWTh Monday, Tuesday, Wednesday, Thursday 7:00 PM–10:00 PM', 'FA 004', 'Staff', 10, NULL, 'Laboratory', '1', 'FINE ARTS', ARRAY[]::TEXT[], 'Reserved for graduate studio independent study, usually outside of the area concentration. Faculty and student consultations will determine the project and credit hours to be assigned.', ARRAY[]::TEXT[], NULL),
    ('SOAD-U 700', 'ADVANCED STUDIO PROJECTS', '12461', 'Class Status', 'F Friday 1:00 PM–5:00 PM', 'FA 004', 'Staff', 15, NULL, 'Laboratory', '1', 'FINE ARTS', ARRAY[]::TEXT[], 'Reserved for graduate studio independent study, usually outside of the area concentration. Faculty and student consultations will determine the project and credit hours to be assigned.', ARRAY[]::TEXT[], NULL),
    ('SOAD-U 700', 'ADVANCED STUDIO PROJECTS', '8243', 'Class Status', NULL, NULL, 'Malcolm Smith', 19, NULL, 'Laboratory', '1', 'FINE ARTS', ARRAY[]::TEXT[], 'Reserved for graduate studio independent study, usually outside of the area concentration. Faculty and student consultations will determine the project and credit hours to be assigned.', ARRAY[]::TEXT[], NULL),
    ('SOAD-W 200', 'DESIGN PRACTICE', '11538', 'Class Status', 'MW Monday, Wednesday 12:45 PM–3:15 PM', 'VD 200', 'Jonathan Racek', 35, NULL, 'Lecture', '3', 'ESKENAZI SCHL / MIES VAN DER R', ARRAY[]::TEXT[], 'Students gain a working understanding of methods for thinking about problems and solutions through a human-centered approach. Students explore the entire design process, including problem scoping, defining, researching, modeling, prototyping, producing, and testing, resulting in viable human-centered, transparent, and imaginative solutions.', ARRAY[]::TEXT[], NULL),
    ('SOAD-W 300', 'DESIGN IN CONTEXT AND CULTURE', '9608', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'FA 102', 'Hassnaa Mohammed', 18, NULL, 'Lecture', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'Students explore the relationships between design, context, and culture. Based on user research, students will create a series of cultural and context-based artifacts that will help them to analyze and design strategies and specific experiences within their design.', ARRAY[]::TEXT[], NULL),
    ('SOAD-W 400', 'DESIGN CAPSTONE', '10502', 'Class Status', 'MW Monday, Wednesday 3:55 PM–6:40 PM', 'KH 017', 'Maxwell Fertik', 6, NULL, 'Lecture', '3', 'KIRKWOOD HALL', ARRAY[]::TEXT[], 'Capstone design studio; students will demonstrate an understanding of project production, research development for integrated design solutions, and creation of expressive, innovative solutions that mediate existing conditions. Includes instruction on how to build professional relationships and develop a compelling personal narrative to aid students in the job search.', ARRAY['COLL (CASE) Career Readiness 2'], NULL),
    ('SOAD-W 400', 'DESIGN CAPSTONE', '13613', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–1:55 PM', 'KH 017', 'Jonathan Racek', 6, NULL, 'Lecture', '3', 'KIRKWOOD HALL', ARRAY[]::TEXT[], 'Capstone design studio; students will demonstrate an understanding of project production, research development for integrated design solutions, and creation of expressive, innovative solutions that mediate existing conditions. Includes instruction on how to build professional relationships and develop a compelling personal narrative to aid students in the job search.', ARRAY['COLL (CASE) Career Readiness 2'], NULL),
    ('SOAD-W 400', 'DESIGN CAPSTONE', '12671', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–5:05 PM', 'KH 017', 'Jonathan Racek', 0, NULL, 'Lecture', '3', 'KIRKWOOD HALL', ARRAY[]::TEXT[], 'Capstone design studio; students will demonstrate an understanding of project production, research development for integrated design solutions, and creation of expressive, innovative solutions that mediate existing conditions. Includes instruction on how to build professional relationships and develop a compelling personal narrative to aid students in the job search.', ARRAY['COLL (CASE) Career Readiness 2'], NULL),
    ('SOAD-W 450', 'DESIGN CAPSTONE II: STUDIO PROJECT', '12672', 'Class Status', 'MW Monday, Wednesday 3:55 PM–6:40 PM', 'KH 017', 'Maxwell Fertik', 6, NULL, 'Lecture', '3', 'KIRKWOOD HALL', ARRAY[]::TEXT[], 'Students, working individually or in teams, will complete complex projects that resolve issues of design on multiple scale levels and across systems. By the end of the course, students will demonstrate a understanding of project production, the development of an integrated design solution, and the creation of an expressive and innovative solution that mediates existing conditions.', ARRAY[]::TEXT[], NULL),
    ('SOAD-W 450', 'DESIGN CAPSTONE II: STUDIO PROJECT', '13614', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–1:55 PM', 'KH 017', 'Jonathan Racek', 6, NULL, 'Lecture', '3', 'KIRKWOOD HALL', ARRAY[]::TEXT[], 'Students, working individually or in teams, will complete complex projects that resolve issues of design on multiple scale levels and across systems. By the end of the course, students will demonstrate a understanding of project production, the development of an integrated design solution, and the creation of an expressive and innovative solution that mediates existing conditions.', ARRAY[]::TEXT[], NULL),
    ('SOAD-W 450', 'DESIGN CAPSTONE II: STUDIO PROJECT', '12673', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–5:05 PM', 'KH 017', 'Jonathan Racek', 0, NULL, 'Lecture', '3', 'KIRKWOOD HALL', ARRAY[]::TEXT[], 'Students, working individually or in teams, will complete complex projects that resolve issues of design on multiple scale levels and across systems. By the end of the course, students will demonstrate a understanding of project production, the development of an integrated design solution, and the creation of an expressive and innovative solution that mediates existing conditions.', ARRAY[]::TEXT[], NULL),
    ('SOAD-X 371', 'UNDERGRADUATE TEACHING INTERNSHIP IN THE SCHOOL OF ART, ARCHITECTURE + DESIGN', '8060', 'Class Status', NULL, NULL, 'Mary Embry', 10, NULL, 'Internship', '1–3', NULL, ARRAY[]::TEXT[], 'Students assist in the preparation and implementation of an undergraduate course under the guidance of a faculty member. Interns do not assist with grading.', ARRAY[]::TEXT[], NULL),
    ('SOAD-X 373', 'INTERNSHIP IN PROFESSIONAL PRACTICE', '8039', 'Class Status', NULL, NULL, 'Martha MacLeish', 10, NULL, 'Internship', '1–3', NULL, ARRAY[]::TEXT[], 'Provides SOAD majors an off-campus supervised and coordinated career-work experience in a cooperating business, a consumer agency, or other related fields.', ARRAY[]::TEXT[], NULL),
    ('SOAD-X 373', 'INTERNSHIP IN PROFESSIONAL PRACTICE', '8726', 'Class Status', NULL, NULL, 'Mary Embry', 10, NULL, 'Internship', '1–3', NULL, ARRAY[]::TEXT[], 'Provides SOAD majors an off-campus supervised and coordinated career-work experience in a cooperating business, a consumer agency, or other related fields.', ARRAY[]::TEXT[], NULL),
    ('SOAD-X 376', 'PRACTICUM IN THE RETAIL INDUSTRY', '5446', 'Class Status', NULL, NULL, 'Minjeong Kim', 20, NULL, 'Practicum', '1–3', NULL, ARRAY[]::TEXT[], 'Provides apparel merchandising majors a supervised and coordinated work experience in the apparel industry.', ARRAY[]::TEXT[], NULL),
    ('SOAD-X 476', 'PRACTICUM IN COLLECTION MANAGEMENT FOR HISTORIC TEXTILES AND COSTUME', '7679', 'Class Status', NULL, NULL, 'Kelly Richardson', 5, NULL, 'Practicum', '1–3', NULL, ARRAY[]::TEXT[], 'Individual work in selected area of collection management for historic textiles and costume.', ARRAY[]::TEXT[], NULL),
    ('SOAD-X 490', 'INDEPENDENT STUDY IN INTERIOR DESIGN', '7680', 'Class Status', NULL, NULL, 'Kim Dutkosky', 3, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Review, discussion, and evaluation of current trends and issues in interior design; analysis of research.', ARRAY[]::TEXT[], NULL),
    ('SOAD-X 491', 'INDEPENDENT STUDY IN TEXTILES AND APPAREL', '7681', 'Class Status', NULL, NULL, 'Heather Akou', 3, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Independent review, discussion, and evaluation of current trends and issues in apparel or textiles; analysis of research or special project.', ARRAY[]::TEXT[], NULL),
    ('SOAD-X 492', 'INDEPENDENT STUDY IN RETAIL', '6323', 'Class Status', NULL, NULL, 'Minjeong Kim', 4, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Independent course work or project under supervision on problems of special interest.', ARRAY[]::TEXT[], NULL),
    ('SOAD-Z 501', 'ARCHITECTURAL STUDIO 1', '8711', 'Class Status', 'MW Monday, Wednesday 1:00 PM–6:00 PM', 'HD TBA', 'Leticia Pardo Rojo', 11, NULL, 'Studio', '6', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'First architectural studio in the core sequence and focuses on fundamentals of architectural design. A series of interrelated, hands-on exercises challenge students to engage in analytical and critical thinking. Learning objectives include foundational 2D and 3D representation, as well as introduction of key concepts for designing architectural structures and spaces.', ARRAY[]::TEXT[], NULL),
    ('SOAD-Z 511', 'VISUAL STUDIES STUDIO 1', '8712', 'Class Status', 'TuTh Tuesday, Thursday 1:00 PM–6:00 PM', 'HD TBA', 'Thomas Wilson', 11, NULL, 'Studio', '6', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'First visual studies studio in the core sequence where drawing from observation will introduce the issues of composition, scale, proportion, measurement, and shape. Spatial volume by mark, line weight, contour, and tonal drawing will address the fundamentals of visual structure and order', ARRAY[]::TEXT[], NULL),
    ('SOAD-Z 521', 'STRUCTURES 1', '36940', 'Class Status', 'Tu Tuesday 9:00 AM–12:00 PM', 'HD TBA', 'Lucas Brown', 11, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Structures 1 is the first course in a two part sequence focusing on the study of statics and strength of materials for architects. Students will investigate the behavior of structural systems and materials through design exercises, case studies, and load testing of models.', ARRAY[]::TEXT[], NULL),
    ('SOAD-Z 601', 'ARCHITECTURAL STUDIO 3', '9256', 'Class Status', 'TuTh Tuesday, Thursday 1:00 PM–6:00 PM', 'HD TBA', 'Christopher Reinhart', 10, NULL, 'Studio', '6', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Third architectural studio in the core sequence and focuses on advanced critical inquiry and design synthesis through a medium to large-scale, urban project. Concepts from the first two core studios are reinforced, while also introducing analysis of user and regulatory requirements, site conditions, accessible design, and environmental impacts.', ARRAY[]::TEXT[], NULL),
    ('SOAD-Z 611', 'VISUAL STUDIES STUDIO 3', '9257', 'Class Status', 'MW Monday, Wednesday 1:00 PM–6:00 PM', 'HD TBA', 'Silvia Acosta', 10, NULL, 'Studio', '6', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'This is the third visual studies studio in the core sequence. Themes and issues from the preceding studio are continued through investigations of color. Various mediums and approaches, including collage, printmaking, pastels, and painting are introduced.', ARRAY[]::TEXT[], NULL),
    ('SOAD-Z 641', 'ENERGY AND ENVIRONMENTAL SYSTEMS 1', '9258', 'Class Status', 'Tu Tuesday 9:00 AM–12:00 PM', 'HD TBA', 'Christopher Reinhart', 10, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'First in a two-part sequence focusing on a holistic understanding of the relationship between built and natural environments. The course enables future architects to mitigate climate change responsibly by examining established and emerging building systems, and the methods and criteria architects use to assess these systems against environmental performance objectives.', ARRAY[]::TEXT[], NULL),
    ('SOAD-Z 701', 'ARCHITECTURAL STUDIO 5', '9839', 'Class Status', 'MW Monday, Wednesday 1:00 PM–6:00 PM', 'HD TBA', 'Yiwen Yuan', 9, NULL, 'Studio', '6', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'This studio will cover variable topics in advanced architectural inquiry. Learning objectives may address a range of issues, including material studies and fabrication, digital technologies, community engagement, social and cultural contexts, sustainability, or historical and theoretical precedent. Projects will vary in scale and scope while maintaining an iterative design process.', ARRAY[]::TEXT[], NULL),
    ('SOAD-Z 711', 'VISUAL STUDIES STUDIO 5', '36938', 'Class Status', 'TuTh Tuesday, Thursday 1:00 PM–6:00 PM', 'HD TBA', 'Cory Robinson', 9, NULL, 'Studio', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'This advanced 5th Visual Studies studio may cover a range of artistic approaches, materials, and themes through two and three-dimensional work. Topics may overlap with the concurrent architectural design studio.', ARRAY[]::TEXT[], NULL),
    ('SOAD-Z 711', 'VISUAL STUDIES STUDIO 5', '36939', 'Closed', 'TuTh Tuesday, Thursday 1:00 PM–6:00 PM', 'HD TBA', 'Ana Meza', 0, NULL, 'Studio', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'This advanced 5th Visual Studies studio may cover a range of artistic approaches, materials, and themes through two and three-dimensional work. Topics may overlap with the concurrent architectural design studio.', ARRAY[]::TEXT[], NULL),
    ('SOAD-Z 800', 'M ARCH ADVANCED STUDIO PROJECTS', '10825', 'Class Status', NULL, NULL, 'Daniel Martinez', 15, NULL, 'Independent Study', '3', NULL, ARRAY[]::TEXT[], 'Reserved for M. Arch independent study; Faculty and student consultations will determine the project and credit hours to be assigned.', ARRAY[]::TEXT[], NULL),
    ('SOAD-Z 800', 'M ARCH ADVANCED STUDIO PROJECTS', '13070', 'Closed', NULL, NULL, 'Daniel Martinez', 0, NULL, 'Independent Study', '3', NULL, ARRAY[]::TEXT[], 'Reserved for M. Arch independent study; Faculty and student consultations will determine the project and credit hours to be assigned.', ARRAY[]::TEXT[], NULL),
    ('SOAD-Z 807', 'SPECIAL TOPICS IN THEORY AND CRITICISM', '10826', 'Class Status', 'Th Thursday 9:00 AM–12:00 PM', 'HD TBA', 'Daniel Martinez', 9, NULL, 'Studio', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'This is an advanced variable topics course using the case study method to focus on topics allied with theory and criticism across the disciplines of architecture, art and design.', ARRAY[]::TEXT[], NULL),
    ('SOAD-Z 808', 'SPECIAL TOPICS IN FABRICATION AND DIGITAL DESIGN', '12963', 'Closed', 'W Wednesday 9:00 AM–12:00 PM', 'HD TBA', 'Lucas Brown', 0, NULL, 'Studio', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'This is an advanced variable topics course focusing on topics related to fabrication and digital design. This is a project based class.', ARRAY[]::TEXT[], NULL),
    ('SOC-G 599', 'THESIS RESEARCH', '3136', 'Class Status', NULL, NULL, 'Fabio Rojas', 50, NULL, 'Research', '0', NULL, ARRAY[]::TEXT[], 'Master''s students who have enrolled in 30 or more hours of graduate course work applicable to the degree and who have completed all other requirements of the degree except the thesis of final project of performance may enroll in G599. Requires section authorization.', ARRAY[]::TEXT[], NULL),
    ('SOC-G 901', 'ADVANCED RESEARCH', '2969', 'Class Status', NULL, NULL, 'Fabio Rojas', 49, NULL, 'Research', '6', NULL, ARRAY[]::TEXT[], 'Available to graduate students who have completed all course requirements for their doctorates, have passed doctoral qualifying examinations, and have the requisite number of degree credit hours, this course provides the advanced research student with a forum for sharing ideas and problems under the supervision of a senior researcher.', ARRAY[]::TEXT[], NULL),
    ('SOC-S 100', 'INTRODUCTION TO SOCIOLOGY', '6479', 'Class Status', 'MW Monday, Wednesday 5:30 PM–6:45 PM', 'RH 100', 'Kody Steffy', 20, NULL, 'Lecture', '3', 'RAWLES HALL', ARRAY[]::TEXT[], 'Introduction to the concepts and methods of sociology with an emphasis on the understanding of contemporary American society.', ARRAY['Transfer Indiana Initiative
