    ('SOC-S 230', 'SOCIETY AND THE INDIVIDUAL', '13245', 'Class Status', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'WH 121', 'Michael Gannon', 1, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Personality and its development; relationship to culture and communication and to social settings; deviant types.', ARRAY['IUB GenEd S&H credit
COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('SOC-S 315', 'WORK IN THE NEW ECONOMY', '14341', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'BH 005', 'Junghun Han', 7, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Sociological perspective on work roles within such organizations as factory, office, school, government, and welfare agencies; career and occupational mobility in work life; formal and informal organizations within work organizations; labor and management conflict and cooperation; problems of modern industrial workers; and how work has changed over time.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('SOC-S 316', 'SOCIOLOGY OF FAMILIES', '29414', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'BH 104', 'Angelica Loblack', 3, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Exploration of the diversity of family forms, norms and meanings over time and across social contexts. Considers the interrelationship between families and other social institutions; investigates family formation and processes of social reproduction within families as they are shaped by race, class, gender and sexual orientation; examines stability and change in families in response to shifting social and cultural contexts.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('SOC-S 316', 'SOCIOLOGY OF FAMILIES', '5634', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'BH 005', 'Madeleine Meldrum', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Exploration of the diversity of family forms, norms and meanings over time and across social contexts. Considers the interrelationship between families and other social institutions; investigates family formation and processes of social reproduction within families as they are shaped by race, class, gender and sexual orientation; examines stability and change in families in response to shifting social and cultural contexts.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('SOC-S 320', 'DEVIANCE, CONFORMITY, AND SOCIAL CONTROL', '14339', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'BH 104', 'Da Eun Jung', 19, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Analysis of deviance in relation to formal and informal social processes. Emphasis on deviance and conformity as functions of social reactions, rules, and power and conflict.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('SOC-S 324', 'SOCIOLOGY OF MENTAL ILLNESS', '5532', 'Closed', NULL, 'WB WEB', 'Jacob Miller', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Social factors in mental illnesses; incidence and prevalence by social and cultural categories; variations in societal reaction; social organization of treatment organizations.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('SOC-S 325', 'CRIMINOLOGY', '5129', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'SB 150', 'Syndee Knight', 1, NULL, 'Lecture', '3', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'A study of the patterns of crime, strategies for control, and theories of crime causation.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('SOC-S 335', 'RACE AND ETHNIC RELATIONS', '12192', 'Closed', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'BH 203', 'Hyeyoung Kwon', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Relations between racial and ethnic minority and majority groups; psychological, cultural, and structural theories of prejudice and discrimination; comparative analysis of diverse systems of intergroup relations.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Diversity in U.S.'], NULL),
    ('SOC-S 344', 'SOCIOLOGY OF CHILDHOOD', '10025', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'BH 203', 'Hyeyoung Kwon', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Analysis of childhood as a structural form and children as social agents who contribute to societal reproduction and change. Considers the relation of childhood to other social institutions and children''s contributions to society historically and cross-culturally. Examines how social policies in education, family, and work affect children''s lives.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('SOC-S 346', 'TOPICS IN CROSS-CULTURAL SOCIOLOGY', '14364', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'GA 1128', 'Hilary Holbrow', 25, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Study of selected sociological issues with an emphasis on cross-cultural analysis. Specific topics announced each semester; examples include work, family, childhood, religion, and education.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('SOC-S 358', 'SOCIAL INEQUALITIES IN HEALTH AND HEALTH CARE', '29411', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'WH 003', 'Anna Mueller', 1, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Examines the sociological aspects of health, illness, patienthood, medical professionals, and health care systems. What factors create inequalities in health and in medical treatment? Expands understanding of health and illness and of conventional medical and insurance practices, and explores ways to improve health care in America.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Diversity in U.S.'], NULL),
    ('SOC-S 360', 'TOPICS IN SOCIAL POLICY', '29408', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'LH 102', 'Brian Kelly', 49, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Specific topics to be announced, e.g. environmental affairs, urban problems, poverty, population problems.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('SOC-S 360', 'TOPICS IN SOCIAL POLICY', '29839', 'Class Status', NULL, NULL, 'Bernice Pescosolido, Alejandra Capshew', 9, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Specific topics to be announced, e.g. environmental affairs, urban problems, poverty, population problems.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('SOC-S 365', 'HEALTH AND SOCIETY: SOCIOLOGY FOR HEALTH PROFESSIONALS', '29410', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'BH 003', 'Elaine Hernandez, Jacob Miller', 1, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Designed for all students, this course is particularly relevant for those planning a career in health care. Explores current events and social problems, such as the re-emergence of childhood infectious diseases. Uses these examples to discuss sociological topics on the new Medical College Admission Test (MCAT).', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('SOC-S 370', 'RESEARCH METHODS IN SOCIOLOGY', '2971', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'GA 1100', 'Emily Meanwell', 7, 'Lecture', 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'The logic of scientific work in sociology; theory construction; major research designs, including experiments, sample surveys, and ethnographic field studies. Methods of sampling; measurement of variables; and descriptive statistics. Commonly used rates and indices in social research; using software to produce graphical displays and descriptive statistics.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit
Class uses IU eTexts'], NULL),
