    ('SOC-S 371', 'STATISTICS FOR SOCIOLOGY', '4711', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'GA 1100', 'Soocheol Cho', 7, 'Lecture', 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Introduces the logic of statistical inference. Students will learn how to use sample data to reach conclusions about a population of interest by calculating confidence intervals and significance tests. Estimating the effects of multiple independent variables using cross-tabulations and/or regression.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('SOC-S 371', 'STATISTICS FOR SOCIOLOGY', '4713', 'Class Status', 'M Monday 4:20 PM–5:10 PM', 'BH 107', 'Cassie Mead', 1, 'Laboratory', 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Introduces the logic of statistical inference. Students will learn how to use sample data to reach conclusions about a population of interest by calculating confidence intervals and significance tests. Estimating the effects of multiple independent variables using cross-tabulations and/or regression.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('SOC-S 371', 'STATISTICS FOR SOCIOLOGY', '4714', 'Class Status', 'M Monday 5:30 PM–6:20 PM', 'BH 107', 'Cassie Mead', 6, 'Laboratory', 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Introduces the logic of statistical inference. Students will learn how to use sample data to reach conclusions about a population of interest by calculating confidence intervals and significance tests. Estimating the effects of multiple independent variables using cross-tabulations and/or regression.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('SOC-S 371', 'STATISTICS FOR SOCIOLOGY', '4712', 'Closed', 'M Monday 3:10 PM–4:00 PM', 'BH 107', 'Cassie Mead', 0, 'Laboratory', 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Introduces the logic of statistical inference. Students will learn how to use sample data to reach conclusions about a population of interest by calculating confidence intervals and significance tests. Estimating the effects of multiple independent variables using cross-tabulations and/or regression.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('SOC-S 431', 'TOPICS IN SOCIAL PSYCHOLOGY', '13257', 'Closed', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'WH 203', 'Jacob Miller, Fabio Rojas', 0, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Specific topics to be announced, e.g., socialization, self-concept development, small-group structures and processes, interpersonal relations, language and human behavior, attitude formation and change, collective behavior, public opinion, intergroup relations.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit
