    ('SOC-S 500', 'PROSEMINAR IN SOCIOLOGY', '2975', 'Class Status', 'Tu Tuesday 8:45 AM–9:45 AM', 'BH 233', 'Keera Allendorf', 6, NULL, 'Seminar', '1', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Introduction to current sociological interests and concerns through the work of departmental members.', ARRAY[]::TEXT[], NULL),
    ('SOC-S 502', 'LAUNCHING YOUR ACADEMIC CAREER', '2976', 'Class Status', 'Tu Tuesday 10:00 AM–11:00 AM', 'BH 317', 'Keera Allendorf', 4, NULL, 'Seminar', '1', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'In this course, students are introduced to basic issues that are essential for their professional development. Course time is divided between in-class discussions and exercises both in and outside of class. This one-credit course is required of all second-year students and is taken on a pass/fail basis.', ARRAY[]::TEXT[], NULL),
    ('SOC-S 506', 'TEACHING OF UNDERGRADUATE SOCIOLOGY', '2977', 'Class Status', 'W Wednesday 5:00 PM–7:00 PM', 'BH 703', 'Brian Powell', 6, NULL, 'Independent Study', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Required of all teaching associates', ARRAY[]::TEXT[], NULL),
    ('SOC-S 530', 'INTRODUCTION TO SOCIAL PSYCHOLOGY', '12074', 'Class Status', 'Th Thursday 9:30 AM–11:30 AM', 'BH 317', 'Stephen Benard', 2, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Examines the broad range of work in social psychology. Emphasis is placed on the relation between the classic and contemporary literature in the field.', ARRAY[]::TEXT[], NULL),
    ('SOC-S 554', 'STATISTICAL TECHNIQUES IN SOCIOLOGY I', '9351', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'BH 337', 'Jennifer Barber', 6, 'Lecture', 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Statistical analysis of single and multiple equation models with continuous dependent variables. May include techniques such as bivariate and multivariate regression, recursive and non-recursive structural equation models.', ARRAY[]::TEXT[], NULL),
    ('SOC-S 554', 'STATISTICAL TECHNIQUES IN SOCIOLOGY I', '9352', 'Class Status', 'TuTh Tuesday, Thursday 5:30 PM–7:30 PM', 'BH 108', 'Yunmyung Cho', 6, 'Laboratory', 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Statistical analysis of single and multiple equation models with continuous dependent variables. May include techniques such as bivariate and multivariate regression, recursive and non-recursive structural equation models.', ARRAY[]::TEXT[], NULL),
    ('SOC-S 558', 'ADVANCED RESEARCH TECHNIQUES', '2978', 'Class Status', 'W Wednesday 9:30 AM–11:45 AM', 'BH 803', 'Koji Chavez', 7, NULL, 'Seminar', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'The logic of analysis including development of research questions, relationship between theory and evidence, research design, sampling, data collection strategies, reliability and validity, measurement, analysis, and drawing conclusions. Also includes an overview of data collection techniques such as surveys, interviews, field methods, and the use of archival and secondary data.', ARRAY[]::TEXT[], NULL),
    ('SOC-S 568', 'SOCIOLOGICAL RESEARCH PRACTICUM III', '29392', 'Class Status', NULL, NULL, 'Andrew Halpern-Manners', 4, NULL, 'Lecture', '1–3', NULL, ARRAY[]::TEXT[], 'Participation in all aspects of a sociological research project, including conceptualization and design, data collection, analysis, and report writing.', ARRAY[]::TEXT[], NULL),
    ('SOC-S 569', 'M A THESIS', '2980', 'Class Status', NULL, NULL, 'Fabio Rojas', 20, NULL, 'Independent Study', '1–6', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('SOC-S 660', 'ADVANCED TOPICS', '29407', 'Class Status', 'M Monday 9:30 AM–11:30 AM', 'BH 740B', 'Jennifer Lee', 7, NULL, 'Lecture', '2–6', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Topics announced when course is to be offered.', ARRAY[]::TEXT[], NULL),
    ('SOC-S 864', 'READINGS IN SOCIOLOGY', '2981', 'Class Status', NULL, NULL, 'Fabio Rojas', 28, NULL, 'Independent Study', '1–12', NULL, ARRAY[]::TEXT[], 'Individualized readings in sociology under faculty supervision.', ARRAY[]::TEXT[], NULL),
    ('SOC-S 864', 'READINGS IN SOCIOLOGY', '9701', 'Class Status', NULL, NULL, 'Fabio Rojas', 30, NULL, 'Independent Study', '1–12', NULL, ARRAY[]::TEXT[], 'Individualized readings in sociology under faculty supervision.', ARRAY[]::TEXT[], NULL),
    ('SOC-S 864', 'READINGS IN SOCIOLOGY', '9808', 'Class Status', NULL, NULL, 'Fabio Rojas', 30, NULL, 'Independent Study', '1–12', NULL, ARRAY[]::TEXT[], 'Individualized readings in sociology under faculty supervision.', ARRAY[]::TEXT[], NULL),
    ('SOC-S 866', 'RESEARCH IN SOCIOLOGY', '2982', 'Class Status', NULL, NULL, 'Fabio Rojas', 25, NULL, 'Independent Study', '1–12', NULL, ARRAY[]::TEXT[], 'Individual research projects in sociology with faculty supervision.', ARRAY[]::TEXT[], NULL),
    ('SOC-S 869', 'PH D THESIS', '2983', 'Class Status', NULL, NULL, 'Fabio Rojas', 41, NULL, 'Independent Study', '1–12', NULL, ARRAY[]::TEXT[], 'Academic credits for work associated with PhD dissertation.', ARRAY[]::TEXT[], NULL),
    ('SOC-S 869', 'PH D THESIS', '9323', 'Class Status', NULL, NULL, 'Fabio Rojas', 27, NULL, 'Independent Study', '1–12', NULL, ARRAY[]::TEXT[], 'Academic credits for work associated with PhD dissertation.', ARRAY[]::TEXT[], NULL),
    ('SOC-X 371', 'UNDERGRADUATE TEACHING ASSISTANTSHIP', '13659', 'Class Status', NULL, NULL, 'Spencer Headworth', 38, NULL, 'Independent Study', '3', NULL, ARRAY[]::TEXT[], 'Faculty-directed experience in academic teaching of an undergraduate course. Students assist with course administration and participate in activities such as holding office hours, leading discussion groups, holding review sections. Specific responsibilities vary by instructor.', ARRAY[]::TEXT[], NULL),
    ('SOC-X 373', 'INTERNSHIP IN PROFESSIONAL PRACTICE', '2984', 'Class Status', NULL, NULL, 'Spencer Headworth', 20, NULL, 'Lecture', '1–3', NULL, ARRAY[]::TEXT[], 'Provides opportunities for students to receive credit for selected, career-related work in a cooperating institution, agency, or business. Research paper that relates work experience to materials learned in sociology courses is required. Evaluation by employer and DUS in Sociology.', ARRAY[]::TEXT[], NULL),
    ('SOC-X 477', 'FIELD EXPERIENCE IN SOCIOLOGY', '7239', 'Class Status', NULL, NULL, 'Spencer Headworth', 20, NULL, 'Independent Study', '1–6', NULL, ARRAY[]::TEXT[], 'Faculty-directed study of aspects of sociology based on field experience in conjunction with directed readings and writings. Specifically, each intern is required to 1) keep a daily or weekly journal, which is given at regular intervals to the faculty sponsor; 2) give an oral report once the fieldwork is completed; 3) depending on academic credit, write a journal or analytic paper or both.', ARRAY[]::TEXT[], NULL),
    ('SOC-X 490', 'INDIVIDUAL READINGS IN SOCIOLOGY', '7241', 'Class Status', NULL, NULL, 'Spencer Headworth', 10, NULL, 'Independent Study', '1–6', NULL, ARRAY[]::TEXT[], 'Individualized approach to selected topics through the use of guided readings, research and critical evaluation. Prior arrangement required; conducted under the supervision of a member of the sociology faculty.', ARRAY[]::TEXT[], NULL),
    ('SOC-X 490', 'INDIVIDUAL READINGS IN SOCIOLOGY', '37206', 'Closed', NULL, NULL, 'Kody Steffy', 0, NULL, 'Independent Study', '1–6', NULL, ARRAY[]::TEXT[], 'Individualized approach to selected topics through the use of guided readings, research and critical evaluation. Prior arrangement required; conducted under the supervision of a member of the sociology faculty.', ARRAY[]::TEXT[], NULL),
    ('SOC-X 498', 'SOCIOLOGICAL RESEARCH I', '12894', 'Class Status', NULL, NULL, 'Spencer Headworth', 2, NULL, 'Seminar', '3', NULL, ARRAY[]::TEXT[], 'Participation in all aspects of a sociological research project, including conceptualization and design, data collection, analysis, and report writing.', ARRAY[]::TEXT[], NULL),
    ('SOC-X 498', 'SOCIOLOGICAL RESEARCH I', '37207', 'Closed', NULL, NULL, 'Kody Steffy', 0, NULL, 'Seminar', '3', NULL, ARRAY[]::TEXT[], 'Participation in all aspects of a sociological research project, including conceptualization and design, data collection, analysis, and report writing.', ARRAY[]::TEXT[], NULL),
    ('SOC-X 498', 'SOCIOLOGICAL RESEARCH I', '37208', 'Closed', NULL, NULL, 'Emily Meanwell', 0, NULL, 'Seminar', '3', NULL, ARRAY[]::TEXT[], 'Participation in all aspects of a sociological research project, including conceptualization and design, data collection, analysis, and report writing.', ARRAY[]::TEXT[], NULL),
    ('SPAN-T 530', 'SPANISH THROUGH CULTURAL EXPRESSIONS', '33310', 'Class Status', NULL, 'OL ONLINE', 'Mindy Badia', 5, NULL, 'Lecture', '3', 'Online Class', ARRAY[]::TEXT[], 'This graduate level course explores the cultures of Spain and Latin America. Through readings, discussion and projects, students will develop the knowledge and skills necessary to incorporate intercultural awareness into their teaching. Students will interpret works of art, architecture, music, film, traditions and attitudes, based on cultural contexts.', ARRAY[]::TEXT[], NULL),
    ('SPAN-T 540', 'SPANISH PHONETICS', '33552', 'Class Status', NULL, 'OL ONLINE', 'Iker Zulaica', 10, NULL, 'Discussion', '3', 'Online Class', ARRAY[]::TEXT[], 'Spanish Phonetics is a course specially designed for current teachers of K-12 Spanish courses. Primary goals are to increase student understanding of the Spanish sound system and variations, provide space to reflect on teaching the Spanish sound system to K-12, and to improve their own pronunciation.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPCN-F 560', 'PUBLIC FINANCE & BUDGETING', '32794', 'Class Status', NULL, 'WB WEB', 'Roger Sell', 1, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'The fiscal role of government in a mixed economy, sources of public revenue and credit; administrative, political, and institutional aspects of the budget and the budgetary process; problems and trends in inter-governmental fiscal relations.', ARRAY[]::TEXT[], NULL),
    ('SPCN-I 516', 'PUBLIC MANAGEMENT INFORMATION SYSTEMS', '34210', 'Class Status', NULL, 'WB WEB', 'Esen Tuna', 8, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course focuses on the application of information systems concepts and tools to challenges and opportunities in the public sector. Topics covered will include current trends in information systems; managerial use of information systems; hardware, software, and telecommunications; systems development processes and practices; and strategic and policy issues in IS.', ARRAY[]::TEXT[], NULL),
    ('SPCN-N 557', 'PROPOSAL DEVELOPMENT AND GRANT ADMINISTRATION', '9011', 'Closed', NULL, 'WB WEB', 'Helen Tygret', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course provides the opportunity for each student to develop a complete proposal--through participation in the entire grant application process. The integration of case studies, visual media, printed materials, and class discussions provide students with practical knowledge for writing successful proposals.', ARRAY[]::TEXT[], NULL),
    ('SPCN-P 541', 'BENEFIT COST ANALYSIS', '9012', 'Class Status', NULL, 'WB WEB', 'Kerry Krutilla', 8, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'A course applying benefit-cost analysis to public and environmental policies. The first part of the course develops the foundation of benefit-cost analysis. The second part of the course consists of case studies applying benefit-cost analysis to actual policy decisions.', ARRAY[]::TEXT[], NULL),
    ('SPCN-P 562', 'PUBLIC PROGRAM EVALUATION', '9013', 'Class Status', NULL, 'WB WEB', 'Ashlyn Nelson', 9, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Examination of how the programs of public agencies are proposed, established, operated and evaluated. Discussion of the role and conduct of research in the program process. In addition, techniques of effective evaluation and report presentation are discussed.', ARRAY[]::TEXT[], NULL),
    ('SPCN-V 506', 'STATISTICAL ANALYSIS FOR EFFECTIVE DECISION MAKING', '10548', 'Closed', NULL, 'WB WEB', 'Ashlyn Nelson', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Non-calculus survey of concepts in probability, estimation, and hypothesis testing. Applications of contingency table analysis; analysis of variance, regression, and other statistical techniques. Computer processing of data emphasized.', ARRAY[]::TEXT[], NULL),
    ('SPCN-V 506', 'STATISTICAL ANALYSIS FOR EFFECTIVE DECISION MAKING', '10549', 'Closed', NULL, 'WB WEB', 'Ashlyn Nelson', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Non-calculus survey of concepts in probability, estimation, and hypothesis testing. Applications of contingency table analysis; analysis of variance, regression, and other statistical techniques. Computer processing of data emphasized.', ARRAY[]::TEXT[], NULL),
    ('SPCN-V 512', 'PUBLIC POLICY PROCESS', '10893', 'Class Status', NULL, 'WB WEB', 'David Ehrlich', 6, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'An examination of the role of public affairs professionals in policy processes. Focuses on relationships with political actors in various policy areas.', ARRAY[]::TEXT[], NULL),
    ('SPCN-V 517', 'PUBLIC MANAGEMENT ECONOMICS', '11371', 'Class Status', NULL, 'WB WEB', 'Alberto Ortega', 1, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course focuses on applications of principles and concepts of intermediate microeconomic theory and managerial economics to public-sector management decisions and policy analysis. The course utilizes case studies with the goal of giving students opportunities to recognize economic dimensions inherent in public policy problems and develop an analytical problem-solving orientation.', ARRAY[]::TEXT[], NULL),
    ('SPCN-V 532', 'SOCIAL EQUITY AND JUSTICE IN PUBLIC AFFAIRS', '12327', 'Class Status', NULL, 'WB WEB', 'Jill Nicholson-Crotty', 1, NULL, 'Lecture', '1.5', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course will explore concepts of social equity and justice as a value and a tool, as well as a measure of policy effectiveness. Topics focus on the role of public policy and institutions (e.g., legislatures, courts, and agencies) in addressing issues like structural racism and inequality.', ARRAY[]::TEXT[], NULL),
    ('SPCN-V 532', 'SOCIAL EQUITY AND JUSTICE IN PUBLIC AFFAIRS', '15248', 'Class Status', NULL, 'WB WEB', 'Jill Nicholson-Crotty', 7, NULL, 'Lecture', '1.5', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course will explore concepts of social equity and justice as a value and a tool, as well as a measure of policy effectiveness. Topics focus on the role of public policy and institutions (e.g., legislatures, courts, and agencies) in addressing issues like structural racism and inequality.', ARRAY[]::TEXT[], NULL),
    ('SPCN-V 532', 'SOCIAL EQUITY AND JUSTICE IN PUBLIC AFFAIRS', '36567', 'Class Status', NULL, 'WB WEB', 'Jill Nicholson-Crotty', 5, NULL, 'Lecture', '1.5', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course will explore concepts of social equity and justice as a value and a tool, as well as a measure of policy effectiveness. Topics focus on the role of public policy and institutions (e.g., legislatures, courts, and agencies) in addressing issues like structural racism and inequality.', ARRAY[]::TEXT[], NULL),
    ('SPCN-V 535', 'MANAGING AND LEADING IN PUBLIC AFFAIRS', '12328', 'Class Status', NULL, 'WB WEB', 'Trent Engbers', 2, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'The course allows students to develop skills and competencies to become effective managers and leaders in organizations pursuing the public interest. It draws from the organization theory and organizational behavior, leadership, and public and nonprofit management literatures for insight into the critical role of management and leadership in governance.', ARRAY[]::TEXT[], NULL),
    ('SPCN-V 536', 'RIGHTS AND RESPONSIBILITIES: HOW LAW SHAPES PUBLIC AFFAIRS', '12326', 'Class Status', NULL, 'WB WEB', 'Tara Ali', 1, NULL, 'Lecture', '1.5', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Explanation of law in society and its influence on public-sector operations. Examination of central legal principles shaping American governance including the rule of law, supremacy and preemption, due process and equal protection, statutory interpretation, and judicial review of administrative agency action, among others.', ARRAY[]::TEXT[], NULL),
    ('SPCN-V 536', 'RIGHTS AND RESPONSIBILITIES: HOW LAW SHAPES PUBLIC AFFAIRS', '32797', 'Class Status', NULL, 'WB WEB', 'Tara Ali', 6, NULL, 'Lecture', '1.5', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Explanation of law in society and its influence on public-sector operations. Examination of central legal principles shaping American governance including the rule of law, supremacy and preemption, due process and equal protection, statutory interpretation, and judicial review of administrative agency action, among others.', ARRAY[]::TEXT[], NULL),
    ('SPCN-V 537', 'DESIGNING AND MANAGING COMPLEX PROJECTS', '12329', 'Class Status', NULL, 'WB WEB', 'Laura Littlepage', 3, NULL, 'Lecture', '1.5', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course covers foundational to advanced concepts and specific skills development in critical project management areas, including supervising project scope, time, cost, human resources and communication. This team-based course will include an academic foundation with an emphasis on the use of real-world skills.', ARRAY[]::TEXT[], NULL),
    ('SPCN-V 537', 'DESIGNING AND MANAGING COMPLEX PROJECTS', '15249', 'Class Status', NULL, 'WB WEB', 'Laura Littlepage', 5, NULL, 'Lecture', '1.5', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course covers foundational to advanced concepts and specific skills development in critical project management areas, including supervising project scope, time, cost, human resources and communication. This team-based course will include an academic foundation with an emphasis on the use of real-world skills.', ARRAY[]::TEXT[], NULL),
    ('SPCN-V 537', 'DESIGNING AND MANAGING COMPLEX PROJECTS', '36568', 'Class Status', NULL, 'WB WEB', 'Meredith Dreiman', 5, NULL, 'Lecture', '1.5', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course covers foundational to advanced concepts and specific skills development in critical project management areas, including supervising project scope, time, cost, human resources and communication. This team-based course will include an academic foundation with an emphasis on the use of real-world skills.', ARRAY[]::TEXT[], NULL),
    ('SPCN-V 548', 'EVIDENCE-BASED DECISION MAKING', '14246', 'Closed', NULL, 'WB WEB', 'Jennifer Silva', 0, NULL, 'Lecture', '1.5', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course is designed to teach students about and provide them with practice with gathering information and evidence, and presenting the evidence compellingly and ethically in a way that informs decision-making.', ARRAY[]::TEXT[], NULL),
    ('SPCN-V 548', 'EVIDENCE-BASED DECISION MAKING', '32813', 'Closed', NULL, 'WB WEB', 'Jennifer Silva', 0, NULL, 'Lecture', '1.5', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course is designed to teach students about and provide them with practice with gathering information and evidence, and presenting the evidence compellingly and ethically in a way that informs decision-making.', ARRAY[]::TEXT[], NULL),
    ('SPCN-V 550', 'TOPICS IN PUBLIC AFFAIRS', '10411', 'Class Status', NULL, 'WB WEB', 'Osita Afoaku', 22, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Selected research and discussion topics organized on a semester-by-semester basis, usually with significant student input in the course design.', ARRAY[]::TEXT[], NULL),
    ('SPCN-V 580', 'READINGS IN PUBLIC AFFAIRS', '10412', 'Class Status', NULL, 'WB WEB', 'Jill Nicholson-Crotty', 30, NULL, 'Readings', '1–6', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Readings on selected topics in public affairs.', ARRAY[]::TEXT[], NULL),
    ('SPCN-V 600', 'CAPSTONE IN PUBLIC AND ENVIRONMENTAL AFFAIRS', '14683', 'Class Status', NULL, 'WB WEB', 'Jennifer Brass, Kathy Fisher', 2, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Interdisciplinary course designed to give students exposure to the realities of the policy process through detailed analyses of case studies and projects. Course integrates science, technology, policy, and management. Topic may vary from semester to semester.', ARRAY[]::TEXT[], NULL),
    ('SPEA-A 163', 'INTRODUCTION TO ARTS MANAGEMENT', '4381', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'PV 272', 'Ursula Kuhar', 12, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'This course is for students considering a career in the arts or interested in arts management fundamentals. Topics include public policy in the arts, the economic structure of arts markets, and issues that arts administrators face as a bridge between arts organizations and audiences.', ARRAY['IUB GenEd S&H credit'], NULL),
    ('SPEA-A 163', 'INTRODUCTION TO ARTS MANAGEMENT', '8986', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'BH 005', 'Sarah Hatcher', 10, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'This course is for students considering a career in the arts or interested in arts management fundamentals. Topics include public policy in the arts, the economic structure of arts markets, and issues that arts administrators face as a bridge between arts organizations and audiences.', ARRAY['IUB GenEd S&H credit'], NULL),
    ('SPEA-A 236', 'MUSIC INDUSTRY I', '9648', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'GA 1106', 'Oliver Nelson', 7, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'The purposes of this class is to gain a historical overview on the development of the music industry from its beginnings to current issues. Special focus will be on the development of legal issues and the recording industry.', ARRAY[]::TEXT[], NULL),
    ('SPEA-A 241', 'COMMUNITY ENGAGEMENT IN THE ARTS', '4380', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'PV 272', 'Ursula Kuhar', 16, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Students will get to know arts organizations and music business entities in the area in order to gain awareness about the role of the Arts in a community as a cultural, social, as well as economic force. Class instruction includes lectures, guest speakers, field trips and practical experiences.', ARRAY[]::TEXT[], NULL),
    ('SPEA-A 354', 'ARTS MARKETING FUNDAMENTALS', '4498', 'Closed', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'WH 002', 'Sarah Hatcher', 0, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'This course introduces students to the essentials of arts marketing: how nonprofit organizations and consumers behave and what strategies marketers can use to successfully operate in today''s environment. Course will examine such topics as the marketing process for product-centered cultural enterprises, collection and use of marketing information, target marketing, and position.', ARRAY[]::TEXT[], NULL),
    ('SPEA-A 450', 'CONTEMPORARY TOPICS IN ARTS ADMINISTRATION', '8604', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'HD TBA', 'Adrian Starnes', 1, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Extensive analysis of selected contemporary topics in Arts Administration. Topics vary from semester to semester.', ARRAY[]::TEXT[], NULL),
    ('SPEA-A 450', 'CONTEMPORARY TOPICS IN ARTS ADMINISTRATION', '11313', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'WH 008', 'Sarah Hatcher', 0, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Extensive analysis of selected contemporary topics in Arts Administration. Topics vary from semester to semester.', ARRAY[]::TEXT[], NULL),
    ('SPEA-A 459', 'PUBLIC POLICY AND THE ARTS', '30463', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:55 PM', 'PV 277', 'Karen Gahl-Mills', 17, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'This course considers the principal aspects of cultural policy in the U.S. and elsewhere. Topics include art education, the ends and means of government funding for the arts, multiculturalism, freedom of expression, copyright, other legal rights of artists, international trade in cultural goods, and international treaties on cultural diversity.', ARRAY[]::TEXT[], NULL),
    ('SPEA-D 573', 'DEVELOPMENT ECONOMICS', '6452', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'PV 163', 'Anh Tran', 1, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'This course will give students a firm understanding about developing economies and some of their pressing issues. It will provide conceptual, theoretical and empirical exposure on key topics, problems, policies and actors.', ARRAY[]::TEXT[], NULL),
    ('SPEA-D 577', 'INTERNATIONAL ECONOMIC STRATEGIES AND TRADE POLICY', '6455', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'PV A335', 'Joseph Ryan, Anh Tran', 16, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Examination of topics in international economics as related to problems of economic development policy. Topics include international trade, comparative economic policy, economic integration, foreign aid investment, exchange rates, and international economic organizations.', ARRAY[]::TEXT[], NULL),
    ('SPEA-E 183', 'ENVIRONMENT AND PEOPLE', '8468', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'BQ C129', 'Marta Venier', 1, NULL, 'Lecture', '3', 'BRISCOE QUAD', ARRAY[]::TEXT[], 'Environment and people is an introductory course that examines how humans interact with their environment. This course covers multiple topics, centered-around human-environment dimensions of environmental change. The overarching objective is to develop an understanding of our impact on the planet and possible solutions to environmental degradation.', ARRAY['IUB GenEd S&H credit'], NULL),
    ('SPEA-E 183', 'ENVIRONMENT AND PEOPLE', '12285', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'PV 276', 'Apoorva Gurtu', 1, NULL, 'Lecture', '3', 'BRISCOE QUAD', ARRAY[]::TEXT[], 'Environment and people is an introductory course that examines how humans interact with their environment. This course covers multiple topics, centered-around human-environment dimensions of environmental change. The overarching objective is to develop an understanding of our impact on the planet and possible solutions to environmental degradation.', ARRAY['IUB GenEd S&H credit'], NULL),
    ('SPEA-E 183', 'ENVIRONMENT AND PEOPLE', '36463', 'Class Status', 'MW Monday, Wednesday 8:00 AM–9:15 AM', 'PV 277', 'Antung Liu', 4, NULL, 'Lecture', '3', 'BRISCOE QUAD', ARRAY[]::TEXT[], 'Environment and people is an introductory course that examines how humans interact with their environment. This course covers multiple topics, centered-around human-environment dimensions of environmental change. The overarching objective is to develop an understanding of our impact on the planet and possible solutions to environmental degradation.', ARRAY['IUB GenEd S&H credit'], NULL),
    ('SPEA-E 183', 'ENVIRONMENT AND PEOPLE', '8418', 'Closed', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'PV 276', 'Tess Leuthner', 0, NULL, 'Lecture', '3', 'BRISCOE QUAD', ARRAY[]::TEXT[], 'Environment and people is an introductory course that examines how humans interact with their environment. This course covers multiple topics, centered-around human-environment dimensions of environmental change. The overarching objective is to develop an understanding of our impact on the planet and possible solutions to environmental degradation.', ARRAY['IUB GenEd S&H credit'], NULL),
