    ('SPEA-E 183', 'ENVIRONMENT AND PEOPLE', '8471', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'BH 203', 'Lindsey Rasnake', 0, NULL, 'Lecture', '3', 'BRISCOE QUAD', ARRAY[]::TEXT[], 'Environment and people is an introductory course that examines how humans interact with their environment. This course covers multiple topics, centered-around human-environment dimensions of environmental change. The overarching objective is to develop an understanding of our impact on the planet and possible solutions to environmental degradation.', ARRAY['IUB GenEd S&H credit'], NULL),
    ('SPEA-E 183', 'ENVIRONMENT AND PEOPLE', '9741', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'PV 276', 'Gwen White', 0, NULL, 'Lecture', '3', 'BRISCOE QUAD', ARRAY[]::TEXT[], 'Environment and people is an introductory course that examines how humans interact with their environment. This course covers multiple topics, centered-around human-environment dimensions of environmental change. The overarching objective is to develop an understanding of our impact on the planet and possible solutions to environmental degradation.', ARRAY['IUB GenEd S&H credit'], NULL),
    ('SPEA-E 183', 'ENVIRONMENT AND PEOPLE', '30469', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'PV 277', 'Antung Liu', 0, NULL, 'Lecture', '3', 'BRISCOE QUAD', ARRAY[]::TEXT[], 'Environment and people is an introductory course that examines how humans interact with their environment. This course covers multiple topics, centered-around human-environment dimensions of environmental change. The overarching objective is to develop an understanding of our impact on the planet and possible solutions to environmental degradation.', ARRAY['IUB GenEd S&H credit'], NULL),
    ('SPEA-E 260', 'INTRODUCTION TO WATER RESOURCES', '10155', 'Class Status', 'TuTh Tuesday, Thursday 5:30 PM–6:45 PM', 'PV 278', 'Garth Lindner', 28, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('SPEA-E 272', 'INTRODUCTION TO ENVIRONMENTAL SCIENCES', '8420', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'PV 276', 'Jon Eldon', 1, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Application of principles from life and physical sciences to the understanding and management of the environment. Emphasis will be placed on (1) the physical and biological restraints on resource availability and use, and (2) the technological and scientific options to solving environmental problems.', ARRAY['IUB GenEd N&M credit - Natural Science'], NULL),
    ('SPEA-E 272', 'INTRODUCTION TO ENVIRONMENTAL SCIENCES', '30470', 'Closed', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'GA 1134', 'Rafael Almeida', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Application of principles from life and physical sciences to the understanding and management of the environment. Emphasis will be placed on (1) the physical and biological restraints on resource availability and use, and (2) the technological and scientific options to solving environmental problems.', ARRAY['IUB GenEd N&M credit - Natural Science'], NULL),
    ('SPEA-E 311', 'INTRODUCTION TO RISK ASSESSMENT AND RISK COMMUNICATION', '4521', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'PV 277', 'Diane Henshel', 17, 'Lecture', 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'This course will cover basic human health and risk assessment procedures, as outlined by the various regulatory agencies (especially EPA) and standards setting groups. As risk communication is an integral part of any risk management process, risk communication techniques and applications will be integrated into the course material.', ARRAY[]::TEXT[], NULL),
    ('SPEA-E 311', 'INTRODUCTION TO RISK ASSESSMENT AND RISK COMMUNICATION', '11450', 'Class Status', 'W Wednesday 5:30 PM–6:45 PM', 'PV 163', 'Diane Henshel', 13, 'Discussion', 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'This course will cover basic human health and risk assessment procedures, as outlined by the various regulatory agencies (especially EPA) and standards setting groups. As risk communication is an integral part of any risk management process, risk communication techniques and applications will be integrated into the course material.', ARRAY[]::TEXT[], NULL),
    ('SPEA-E 311', 'INTRODUCTION TO RISK ASSESSMENT AND RISK COMMUNICATION', '11451', 'Class Status', 'Tu Tuesday 5:30 PM–6:45 PM', 'PV 163', 'Diane Henshel', 4, 'Discussion', 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'This course will cover basic human health and risk assessment procedures, as outlined by the various regulatory agencies (especially EPA) and standards setting groups. As risk communication is an integral part of any risk management process, risk communication techniques and applications will be integrated into the course material.', ARRAY[]::TEXT[], NULL),
    ('SPEA-E 332', 'INTRODUCTION TO APPLIED ECOLOGY', '3653', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'PV 273', 'Stephen Glaholt', 4, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], NULL, ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-E 332', 'INTRODUCTION TO APPLIED ECOLOGY', '9002', 'Closed', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'PV A205', 'Jon Eldon', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], NULL, ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-E 340', 'ENVIRONMENTAL ECONOMICS AND FINANCE', '8594', 'Closed', 'TuTh Tuesday, Thursday 5:30 PM–6:45 PM', 'PV A201', 'Kerry Krutilla', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'This course familiarized students with the principles of environmental economics, finance, and cost-benefit analysis. The incentive effects of environmental policy design are assessed. Policy instruments include tradable permits, emissions taxes, deposit-refund systems, pollution prevention programs, and voluntary agreements. Project appraisal techniques are then developed, and applied to specific case evaluations.', ARRAY[]::TEXT[], NULL),
    ('SPEA-E 340', 'ENVIRONMENTAL ECONOMICS AND FINANCE', '30473', 'Closed', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'PV 278', 'Nilesh Shinde', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'This course familiarized students with the principles of environmental economics, finance, and cost-benefit analysis. The incentive effects of environmental policy design are assessed. Policy instruments include tradable permits, emissions taxes, deposit-refund systems, pollution prevention programs, and voluntary agreements. Project appraisal techniques are then developed, and applied to specific case evaluations.', ARRAY[]::TEXT[], NULL),
    ('SPEA-E 363', 'ENVIRONMENTAL MANAGEMENT', '13840', 'Class Status', 'Th Thursday 6:00 PM–8:30 PM', 'JH A106', 'Brooke Fox', 5, NULL, 'Lecture', '3', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], NULL, ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-E 363', 'ENVIRONMENTAL MANAGEMENT', '2985', 'Closed', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'GA 0003', 'Marc Lame', 0, NULL, 'Lecture', '3', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], NULL, ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-E 363', 'ENVIRONMENTAL MANAGEMENT', '8473', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'PV A223', 'Mary Willett', 0, NULL, 'Lecture', '3', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], NULL, ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-E 400', 'TOPICS IN ENVIRONMENTAL STUDIES', '8490', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'SB 220', 'Rhonda Baird', 13, NULL, 'Lecture', '3', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'An interdisciplinary consideration of specific environmental topics.', ARRAY[]::TEXT[], NULL),
    ('SPEA-E 400', 'TOPICS IN ENVIRONMENTAL STUDIES', '9891', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'PV 272', 'Nikolaos Zirogiannis', 6, NULL, 'Lecture', '3', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'An interdisciplinary consideration of specific environmental topics.', ARRAY[]::TEXT[], NULL),
    ('SPEA-E 400', 'TOPICS IN ENVIRONMENTAL STUDIES', '10167', 'Class Status', 'TuTh Tuesday, Thursday 8:00 AM–9:15 AM', 'PV 273', 'Chris Kohler', 14, NULL, 'Lecture', '3', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'An interdisciplinary consideration of specific environmental topics.', ARRAY[]::TEXT[], NULL),
    ('SPEA-E 412', 'RISK COMMUNICATION', '30475', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'PV 272', 'Diane Henshel', 30, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Risk communication is the means by which technical information is communicated to others (the public included), especially in the context of making decisions about environmentally-related policy (such as siting of a landfill). The course emphasizes both theory (in lectures) and practical experience through developing and acting in role-play scenarios.', ARRAY[]::TEXT[], NULL),
    ('SPEA-E 416', 'FISHERIES MANAGEMENT', '13841', 'Class Status', 'MW Monday, Wednesday 6:30 PM–7:45 PM', 'PV A205', 'Sandy Clark-Kolaks', 17, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Teaches the processes for managing fisheries in a variety of environments. Covers basics of fish biology, ecology, and management, with an emphasis on public involvement. Students will explore quantitative fisheries methods, including population dynamics and management strategy evaluation, and presentation of scientific information in written and spoken form.', ARRAY[]::TEXT[], NULL),
    ('SPEA-E 418', 'VECTOR-BASED GIS', '4303', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'PV 151', 'Avram Primack', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Introduction to geographic information systems using vector data structure Vector GIS capabilities and uses. Data structure and file management of spatial data. Laboratory exercises using ARC/INFO software.', ARRAY[]::TEXT[], NULL),
    ('SPEA-E 422', 'URBAN FOREST MANAGEMENT', '8989', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'HD TBA', 'Sarah Mincey', 0, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Originally an outgrowth of arboriculture, urban forestry now encompasses the broader concepts of managing the trees, forests, and other natural resources of cities for ecological, economic and social benefits. Lectures, discussions and field projects will by supplemented by outside speakers.', ARRAY[]::TEXT[], NULL),
    ('SPEA-E 431', 'WATER SUPPLY AND WASTEWATER TREATMENT', '30476', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'BQ C129', 'Tyler Balson', 0, NULL, 'Lecture', '3', 'BRISCOE QUAD', ARRAY[]::TEXT[], 'Health and ecological premises for water and wastewater treatment; principles of water supply; treatment, distribution, and construction; basis for water standards and laboratory examinations; wastewater disposal methods and construction for private installations, institutions, municipalities, and industries; water quality control with respect to wastewater pollution.', ARRAY[]::TEXT[], NULL),
    ('SPEA-E 440', 'WETLANDS ECOLOGY AND MANAGEMENT', '13842', 'Closed', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'PV 275 PV 275', 'Jacob Bannister', 0, NULL, 'Lecture', '4', 'SPEA', ARRAY[]::TEXT[], 'This course focuses on structural and functional characteristics of wetlands, their importance as a natural resource and value to society. Topics include characteristics used to identify and classify wetlands, adaptations for living in wetlands, community structure and ecosystem processes, functions and values. Management of wetlands includes jurisdictional delineation, wetland assessment, and hydrogeomorphic assessment.', ARRAY[]::TEXT[], NULL),
    ('SPEA-E 442', 'HABITAT ANALYSIS-TERRESTRIAL', '30477', 'Class Status', 'W Wednesday 2:20 PM–3:35 PM', 'PV A203 PV A203', 'Jon Eldon', 12, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'This is an experiential field methods course. Students work as teams collecting field data to test hypotheses about forest habitats. Students will learn new methods and field skills in local parks and forests, then prepare scientific reports that incorporate statistical analysis, to be presented in a class symposium.', ARRAY[]::TEXT[], NULL),
    ('SPEA-E 444', 'HAZARDOUS MATERIALS', '10168', 'Class Status', 'TuTh Tuesday, Thursday 8:00 AM–9:15 AM', 'PV 273', 'Chris Kohler', 14, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'This course is designed to provide a general overview of hazardous materials management including history; regulations; basic chemistry; hazardous properties of chemical, biological, and radioactive substances; hazard classifications; hazard controls; personal protection; safe storage; handling; transportation; plus an introduction to hazardous waste; environmental sampling and remediation.', ARRAY[]::TEXT[], NULL),
    ('SPEA-E 452', 'SOLID AND HAZARDOUS WASTE MANAGEMENT', '3446', 'Class Status', 'MW Monday, Wednesday 6:30 PM–7:45 PM', 'PV 278', 'Rex Howard', 16, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Types and sources of solid waste; collection methods; disposal techniques: sanitary landfill, incineration, composting, reclaiming, or recycling; advantages and disadvantages of each; special and hazardous waste handling; operation and management of solid and hazardous waste programs.', ARRAY[]::TEXT[], NULL),
    ('SPEA-E 455', 'LIMNOLOGY', '2986', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'PV 272', 'Sarah Powers', 6, 'Lecture', 'Lecture', '4', 'SPEA', ARRAY[]::TEXT[], 'Limnology is the ecology of inland lakes and streams, combining the principles of biology, chemistry, geology, and physics to understand how they function. The effects of human perturbation on aquatic systems will be highlighted in both lectures and laboratory work to aid student understanding of the concepts involved.', ARRAY[]::TEXT[], NULL),
    ('SPEA-E 455', 'LIMNOLOGY', '2987', 'Class Status', 'F Friday 8:00 AM–12:00 PM', 'PV 272', 'Sarah Powers', 3, 'Laboratory', 'Lecture', '4', 'SPEA', ARRAY[]::TEXT[], 'Limnology is the ecology of inland lakes and streams, combining the principles of biology, chemistry, geology, and physics to understand how they function. The effects of human perturbation on aquatic systems will be highlighted in both lectures and laboratory work to aid student understanding of the concepts involved.', ARRAY[]::TEXT[], NULL),
    ('SPEA-E 455', 'LIMNOLOGY', '2988', 'Class Status', 'F Friday 1:00 PM–5:00 PM', 'PV 272', 'Sarah Powers', 3, 'Laboratory', 'Lecture', '4', 'SPEA', ARRAY[]::TEXT[], 'Limnology is the ecology of inland lakes and streams, combining the principles of biology, chemistry, geology, and physics to understand how they function. The effects of human perturbation on aquatic systems will be highlighted in both lectures and laboratory work to aid student understanding of the concepts involved.', ARRAY[]::TEXT[], NULL),
    ('SPEA-E 457', 'INTRODUCTION TO CONSERVATION BIOLOGY', '8561', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'PV 278', 'Avram Primack', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Ecological principles associated with rare species and with biodiversity, laws and statutes used to conserve biodiversity, and land and species management practices. The aim is to understand scientific and political complexities of conservation biology, and to study different methods used to conserve living resources and resolve conflicts associated with conservation.', ARRAY[]::TEXT[], NULL),
    ('SPEA-E 461', 'WILDLIFE TECHNIQUES', '12802', 'Class Status', 'Sa Saturday 8:00 AM–12:00 PM', 'PV 273', 'Michelle Benavidez Westrich, Brad Westrich', 1, NULL, 'Laboratory', '3', 'SPEA', ARRAY[]::TEXT[], 'Study and practice of techniques for wildlife management and research using class labs and field trips. Topics include identification, marking, capture and handling, passive monitoring, population estimation, human dimensions, and responding to disease outbreaks. Further it explores the benefit of incorporating local knowledge into management.', ARRAY[]::TEXT[], NULL),
    ('SPEA-E 490', 'DIRECTED RESEARCH IN ENVIRONMENTAL SCIENCE', '14795', 'Class Status', NULL, NULL, 'Andrea Need', 10, NULL, 'Independent Study', '1–4', NULL, ARRAY[]::TEXT[], 'Individualized laboratory or field-based research in any field of environmental science under the direction of an advising professor. Students are expected to write a report on their research at the end of each semester.', ARRAY[]::TEXT[], NULL),
    ('SPEA-E 490', 'DIRECTED RESEARCH IN ENVIRONMENTAL SCIENCE', '14796', 'Class Status', NULL, NULL, 'Andrea Need', 10, NULL, 'Independent Study', '1–4', NULL, ARRAY[]::TEXT[], 'Individualized laboratory or field-based research in any field of environmental science under the direction of an advising professor. Students are expected to write a report on their research at the end of each semester.', ARRAY[]::TEXT[], NULL),
    ('SPEA-E 513', 'ENVIRONMENTAL PROJECT MANAGEMENT', '11563', 'Class Status', NULL, 'MTuWThF Monday, Tuesday, Wednesday, Thursday, Friday 9:30 AM–11:30 AM MTuWThF Monday, Tuesday, Wednesday, Thursday, Friday 1:00 PM–3:00 PM M Monday 9:30 AM–11:30 AM Intersession 8/4/2025–8/18/2025', 'PV 163 PV 163 PV 163', NULL, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'This course covers foundational to advanced concepts and specific skills development in critical project management areas, including supervising project scope, time, cost, human resources, and communication. This team-based course will focus on environmental sustainability case studies and include an academic foundation with an emphasis on the use of real-world skills.', ARRAY[]::TEXT[], NULL),
    ('SPEA-E 515', 'FUNDAMENTALS OF AIR POLLUTION', '30512', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'PV A203', 'Philip Stevens', 4, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'The purpose of the course is to provide the student with an understanding of the field of air pollution including the behavior of the atmosphere and pollutants in the atmosphere, effects of air pollution, regulatory programs, engineering controls, and air quality management programs.', ARRAY[]::TEXT[], NULL),
    ('SPEA-E 516', 'FISHERIES MANAGEMENT', '13845', 'Class Status', 'MW Monday, Wednesday 6:30 PM–7:45 PM', 'PV A205', 'Sandy Clark-Kolaks', 17, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Teaches the processes for managing fisheries in a variety of environments. Covers basics of fish biology, ecology and management, with an emphasis on public involvement. Students will explore quantitative fisheries methods, including population dynamics and management strategy evaluation, and presentation of scientific information in written and spoken form.', ARRAY[]::TEXT[], NULL),
    ('SPEA-E 518', 'VECTOR-BASED GEOGRAPHIC INFORMATION SYSTEMS', '4302', 'Class Status', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'PV 151', 'Avram Primack', 10, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Geographic information systems using vector data structure. Vector GIS capabilities and uses. Data structure and file management of spatial data. Laboratory exercises using vector-based GIS software such as ARC/INFO.', ARRAY[]::TEXT[], NULL),
    ('SPEA-E 518', 'VECTOR-BASED GEOGRAPHIC INFORMATION SYSTEMS', '13014', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'PV 151', 'Avram Primack', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Geographic information systems using vector data structure. Vector GIS capabilities and uses. Data structure and file management of spatial data. Laboratory exercises using vector-based GIS software such as ARC/INFO.', ARRAY[]::TEXT[], NULL),
    ('SPEA-E 522', 'URBAN FOREST MANAGEMENT', '8990', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'HD TBA', 'Sarah Mincey', 2, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Originally an outgrowth of arboriculture, urban forestry now encompasses the broader concepts of managing the trees, forests, and other natural resources of cities for ecological, economic, and social benefits. Lectures, discussion and field projects will be supplemented by outside speakers.', ARRAY[]::TEXT[], NULL),
    ('SPEA-E 528', 'FOREST ECOLOGY AND MANAGEMENT', '13846', 'Closed', 'W Wednesday 5:30 PM–6:45 PM', 'PV A203 PV A203', 'RD Sample', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Field and laboratory exercises in quantitative analysis of forest ecosystems. Sampling and data collection methodologies, data analysis and interpretation. Concepts in forest ecology and forest management.', ARRAY[]::TEXT[], NULL),
    ('SPEA-E 536', 'ENVIRONMENTAL CHEMISTRY', '8602', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'PV A201', 'Brandon Bottorff', 28, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Gas law calculations, stoichiometry, steady and non-steady state box models, stratospheric ozone, chemical kinetics, photochemical smog, greenhouse effect, CO2 equilibria, chemo-dynamics, pesticides, and toxic metals.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-E 538', 'STATISTICS FOR ENVIRONMENTAL SCIENCE', '5918', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'PV A221 PV A221', 'Mallory Barnes', 7, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Data analysis and statistics for environmental research and policy-making. Logic and illogic of hypothesis testing, with emphasis on power. Sampling and design of experiments. Group comparisons, analysis of variance, regression.', ARRAY[]::TEXT[], NULL),
    ('SPEA-E 540', 'WETLANDS ECOLOGY AND MANAGEMENT', '13847', 'Closed', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'PV 275 PV 275', 'Jacob Bannister', 0, NULL, 'Lecture', '4', 'SPEA', ARRAY[]::TEXT[], 'This course focuses on structural and functional characteristics of wetlands and their importance as a natural resource to society. Topics include characteristics to identify and classify wetlands, adaptations for living in wetlands, community structure, ecosystem processes, functions and values. Management of wetlands includes jurisdictional delineation, wetland assessment, and hydrogeomorphic assessment.', ARRAY[]::TEXT[], NULL),
    ('SPEA-E 542', 'HAZARDOUS MATERIALS', '10169', 'Class Status', 'TuTh Tuesday, Thursday 8:00 AM–9:15 AM', 'PV 273', 'Chris Kohler', 14, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Provides a technical basis for managing hazardous materials. Topics include properties and chemistry of hazardous materials; recognition of potential hazards associated with the use, storage, and transport of these materials; emergency and spill response; health effects; and transportation regulations.', ARRAY[]::TEXT[], NULL),
    ('SPEA-E 543', 'ENVIRONMENTAL MANAGEMENT', '4236', 'Closed', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'PV 278', 'Landon Yoder', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Course introduces advanced management concepts needed for environmental professionals by increasing their understanding regarding: 1) how implementing program, resource and political management relates to environmental issues; 2) the organizational and legal structure/function of environmental management in the United States: 3) how professionals develop a strategic implementation approach toward successfully managing the environment.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-E 543', 'ENVIRONMENTAL MANAGEMENT', '33393', 'Closed', NULL, 'WB WEB', 'Gwen White', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Course introduces advanced management concepts needed for environmental professionals by increasing their understanding regarding: 1) how implementing program, resource and political management relates to environmental issues; 2) the organizational and legal structure/function of environmental management in the United States: 3) how professionals develop a strategic implementation approach toward successfully managing the environment.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-E 554', 'GROUNDWATER FLOW MODELING', '13848', 'Class Status', 'MW Monday, Wednesday 8:00 AM–9:15 AM', 'WB WEB', 'Victor Kelson', 21, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Fundamentals of groundwater flow modeling demonstrated through exercises in one-dimensional and radial flow. Two-dimensional flow is treated by use of a semi-analytic approach. Alternative modeling techniques, such as finite elements and finite differences are discussed. Streamline tracing is discussed to study the spreading of contaminants.', ARRAY[]::TEXT[], NULL),
    ('SPEA-E 555', 'TPCS IN ENVIRONMENTAL SCIENCES', '13849', 'Class Status', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'PV 273', 'Zhiying Li', 5, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('SPEA-E 555', 'TPCS IN ENVIRONMENTAL SCIENCES', '33593', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'PV 163', 'Kimberly Novick', 4, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('SPEA-E 555', 'TPCS IN ENVIRONMENTAL SCIENCES', '33381', 'Class Status', NULL, 'WB WEB', 'Vicky Meretsky', 14, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('SPEA-E 556', 'LIMNOLOGY', '7464', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'PV 272', 'Sarah Powers', 6, 'Lecture', 'Lecture', '4', 'SPEA', ARRAY[]::TEXT[], 'Study of inland waters, including lakes, reservoirs, and rivers. Course covers physical, chemical, and biological aspects of aquatic ecology, including the impacts of human activities on inland waters.', ARRAY[]::TEXT[], NULL),
    ('SPEA-E 556', 'LIMNOLOGY', '7465', 'Class Status', 'F Friday 8:00 AM–12:00 PM', 'PV 272', 'Sarah Powers', 3, 'Laboratory', 'Lecture', '4', 'SPEA', ARRAY[]::TEXT[], 'Study of inland waters, including lakes, reservoirs, and rivers. Course covers physical, chemical, and biological aspects of aquatic ecology, including the impacts of human activities on inland waters.', ARRAY[]::TEXT[], NULL),
    ('SPEA-E 556', 'LIMNOLOGY', '7467', 'Class Status', 'F Friday 1:00 PM–5:00 PM', 'PV 272', 'Sarah Powers', 3, 'Laboratory', 'Lecture', '4', 'SPEA', ARRAY[]::TEXT[], 'Study of inland waters, including lakes, reservoirs, and rivers. Course covers physical, chemical, and biological aspects of aquatic ecology, including the impacts of human activities on inland waters.', ARRAY[]::TEXT[], NULL),
    ('SPEA-E 561', 'WILDLIFE TECHNIQUES', '13850', 'Class Status', 'Sa Saturday 8:00 AM–12:00 PM', 'PV 273', 'Michelle Benavidez Westrich, Brad Westrich', 1, NULL, 'Laboratory', '3', 'SPEA', ARRAY[]::TEXT[], 'Study and practice of techniques for wildlife management and research using class labs and field trips. Topics include identification, marking, capture and handling, passive monitoring, population estimation, human dimensions, and responding to disease outbreaks. Further it explores the benefit of incorporating local knowledge into management.', ARRAY[]::TEXT[], NULL),
    ('SPEA-E 562', 'SOLID AND HAZARDOUS WASTE MANAGEMENT', '2989', 'Class Status', 'MW Monday, Wednesday 6:30 PM–7:45 PM', 'PV 278', 'Rex Howard', 16, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'The purpose is to provide students with a technical foundation in areas of solid and hazardous waste management which can be applied to the examination of policy options. Topics include characterization of the waste stream, regulations, health and environmental risks, liability issues, management technologies and treatment and disposal options.', ARRAY[]::TEXT[], NULL),
    ('SPEA-E 574', 'ENERGY SYSTEMS IN TRANSITION', '5917', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'PV 275', 'Shahzeen Attari', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Graduate level course that introduces the basic technical and regulatory elements of energy systems including characteristics of primary sources, conversion technologies, environmental impacts and commercial/regulatory constraints.', ARRAY[]::TEXT[], NULL),
    ('SPEA-E 579', 'READINGS IN ENVIRONMENTAL SCIENCE', '2990', 'Class Status', NULL, NULL, 'Vicky Meretsky', 48, NULL, 'Readings', '1–6', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('SPEA-E 579', 'READINGS IN ENVIRONMENTAL SCIENCE', '9965', 'Class Status', NULL, NULL, 'Vicky Meretsky', 50, NULL, 'Readings', '1–6', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('SPEA-E 589', 'PRACTICUM IN ENVIRONMENTAL SCIENCE', '2991', 'Class Status', NULL, NULL, 'Celeste Ross', 143, NULL, 'Independent Study', '0–6', NULL, ARRAY[]::TEXT[], 'Professional experience in environmental science with public agencies or private sector firms or organizations. Usually arranged through the Public Careers Internship and Placement Center.', ARRAY[]::TEXT[], NULL),
    ('SPEA-E 625', 'RESEARCH IN ENVIRONMENTAL SCIENCE', '2992', 'Class Status', NULL, NULL, 'Vicky Meretsky', 35, NULL, 'Readings', '1–12', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('SPEA-E 625', 'RESEARCH IN ENVIRONMENTAL SCIENCE', '5311', 'Class Status', NULL, NULL, 'Vicky Meretsky', 50, NULL, 'Readings', '1–12', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('SPEA-E 680', 'SEMINAR IN ENVIRONMENTAL SCIENCE AND POLICY', '2993', 'Class Status', 'Th Thursday 2:20 PM–3:35 PM', 'PV A221', 'Mallory Barnes', 43, NULL, 'Seminar', '1', 'SPEA', ARRAY[]::TEXT[], 'A seminar series on current topics in environmental science and policy.', ARRAY[]::TEXT[], NULL),
    ('SPEA-E 710', 'ADVANCED TOPICS IN ENVIRONMENTAL SCIENCE', '33590', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'SE 105', 'Kimberly Novick', 9, NULL, 'Lecture', '3', 'SWAIN EAST', ARRAY[]::TEXT[], 'For advanced students. Topics will vary and will cover subjects not available in other courses.', ARRAY[]::TEXT[], NULL),
    ('SPEA-E 725', 'RESEARCH IN ENVIRONMENTAL SCIENCE', '12846', 'Class Status', NULL, NULL, 'Marta Venier', 10, NULL, 'Research', '1–12', NULL, ARRAY[]::TEXT[], 'Research on selected topics in environmental science to be arranged with the individual instructor.', ARRAY[]::TEXT[], NULL),
    ('SPEA-E 725', 'RESEARCH IN ENVIRONMENTAL SCIENCE', '12847', 'Class Status', NULL, NULL, 'Marta Venier', 10, NULL, 'Research', '1–12', NULL, ARRAY[]::TEXT[], 'Research on selected topics in environmental science to be arranged with the individual instructor.', ARRAY[]::TEXT[], NULL),
    ('SPEA-E 779', 'READINGS IN ENVIRONMENTAL SCIENCE', '14118', 'Class Status', NULL, NULL, 'Marta Venier', 10, NULL, 'Readings', '1–6', NULL, ARRAY[]::TEXT[], 'Readings on selected topics in environmental science to be arranged with the individual instructor.', ARRAY[]::TEXT[], NULL),
    ('SPEA-E 779', 'READINGS IN ENVIRONMENTAL SCIENCE', '14119', 'Class Status', NULL, NULL, 'Marta Venier', 10, NULL, 'Readings', '1–6', NULL, ARRAY[]::TEXT[], 'Readings on selected topics in environmental science to be arranged with the individual instructor.', ARRAY[]::TEXT[], NULL),
    ('SPEA-E 890', 'PH.D. THESIS: ENVIRONMENTAL SCIENCE', '2994', 'Class Status', NULL, NULL, 'Marta Venier', 50, NULL, 'Independent Study', '1–12', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('SPEA-E 890', 'PH.D. THESIS: ENVIRONMENTAL SCIENCE', '3354', 'Class Status', NULL, NULL, 'Marta Venier', 50, NULL, 'Independent Study', '1–12', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('SPEA-F 560', 'PUBLIC FINANCE & BUDGETING', '6489', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'PV A223', 'Craig Johnson', 8, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'The fiscal role of government in a mixed economy, sources of public revenue and credit; administrative, political, and institutional aspects of the budget and the budgetary process; problems and trends in inter-governmental fiscal relations.', ARRAY[]::TEXT[], NULL),
    ('SPEA-F 610', 'GOVERNMENT BUDGETING AND PROGRAM ANALYSIS', '6491', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'PV A205', 'Temirlan Moldogaziev', 16, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Advanced study of management aspects of budgetary process. Special cases are analyzed and budget problem-solving exercises are utilized.', ARRAY[]::TEXT[], NULL),
    ('SPEA-F 667', 'SEMINAR IN PUBLIC CAPITAL AND DEBT THEORY', '34545', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'PV A203', 'Craig Johnson', 10, NULL, 'Seminar', '3', 'SPEA', ARRAY[]::TEXT[], 'This seminar examines the options open to governments, especially state and local, and why they resort to debt finance. The issues raised by the alternatives are examined in detail. Among the topics are public authority debt, revenue bonds, methods of placement, lease-purchase finance, and maturity choice. In addition, management of idle cash balances will be considered.', ARRAY[]::TEXT[], NULL),
    ('SPEA-F 768', 'SEMINAR IN PUBLIC BUDGETING', '12380', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'PV 273', 'Temirlan Moldogaziev', 11, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'This seminar will examine a body of literature dealing with public sector resource allocation in the U.S. Primary emphasis will be on the budgetary process, the emergence of competing theories of budgeting and contemporary budgeting research. Budgetary systems will be explored at the national, state, and local levels.', ARRAY[]::TEXT[], NULL),
    ('SPEA-G 901', 'ADVANCED RESEARCH', '2995', 'Class Status', NULL, NULL, 'Jennifer Silva', 29, NULL, 'Research', '6', NULL, ARRAY[]::TEXT[], 'Available to graduate students who have completed all course requirements for their doctorates, have passed doctoral qualifying examinations, and have the requisite number of degree credit hours, this course provides the advanced research student with a forum for sharing ideas and problems under the supervision of a senior researcher.', ARRAY[]::TEXT[], NULL),
    ('SPEA-H 124', 'OVERVIEW OF THE U.S. HEALTHCARE SYSTEM', '12947', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'PV 169', 'Patrick McCollam', 7, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'An overview of the U.S. healthcare delivery system. It examines the organization, function, and role of the system; current system problems; and alternative systems or solutions.', ARRAY['IUB GenEd S&H credit
Class uses IU eTexts'], NULL),
