    ('SPEA-H 267', 'CAREER DEVELOPMENT AND PLANNING', '15076', 'Closed', 'MW Monday, Wednesday 11:35 AM–12:25 PM', 'GY 1043', 'Andy Bosk', 0, NULL, 'Lecture', '2', 'SPEA', ARRAY[]::TEXT[], 'Course highlights include: identification of work values and personality preference, career research assignments, networking assignments designed to prepare students for contact with employers, in-depth tutorial and feedback concerning how to craft a marketable resume and cover letter, and development of an overall career development plan.', ARRAY[]::TEXT[], NULL),
    ('SPEA-H 267', 'CAREER DEVELOPMENT AND PLANNING', '30480', 'Closed', 'TuTh Tuesday, Thursday 4:20 PM–5:10 PM', 'AD A152', 'Jennifer Schepers', 0, NULL, 'Lecture', '2', 'SPEA', ARRAY[]::TEXT[], 'Course highlights include: identification of work values and personality preference, career research assignments, networking assignments designed to prepare students for contact with employers, in-depth tutorial and feedback concerning how to craft a marketable resume and cover letter, and development of an overall career development plan.', ARRAY[]::TEXT[], NULL),
    ('SPEA-H 267', 'CAREER DEVELOPMENT AND PLANNING', '30481', 'Closed', 'MW Monday, Wednesday 8:25 AM–9:15 AM', 'PV A201', 'Miranda Redman', 0, NULL, 'Lecture', '2', 'SPEA', ARRAY[]::TEXT[], 'Course highlights include: identification of work values and personality preference, career research assignments, networking assignments designed to prepare students for contact with employers, in-depth tutorial and feedback concerning how to craft a marketable resume and cover letter, and development of an overall career development plan.', ARRAY[]::TEXT[], NULL),
    ('SPEA-H 322', 'PRINCIPLES OF EPIDEMIOLOGY', '5382', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'PV 274', 'Cydney McGuire', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'A basic overview of epidemiologic methodology and techniques. Both communicable and chronic disease risk factors will be discussed, along with data acquisition, analysis techniques, and current published epidemiological studies.', ARRAY[]::TEXT[], NULL),
    ('SPEA-H 324', 'HEALTH POLICY', '7173', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'PV 278', 'Seth Freedman', 4, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'This course will focus on current health policy issues within the context of the United States health care system. The course will familiarize students with the political environment of public policy, introduce major health care policy perspectives, and apply those analytical models to a series of health policy issues.', ARRAY[]::TEXT[], NULL),
    ('SPEA-H 324', 'HEALTH POLICY', '12278', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'PV 278', 'Seth Freedman', 1, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'This course will focus on current health policy issues within the context of the United States health care system. The course will familiarize students with the political environment of public policy, introduce major health care policy perspectives, and apply those analytical models to a series of health policy issues.', ARRAY[]::TEXT[], NULL),
    ('SPEA-H 341', 'LEGAL ASPECTS OF HEALTH CARE ADMINISTRATION', '5276', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'GY 1043', 'Laura Durfee, Bailey Anstead', 2, NULL, 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'An overview of the liability and legal responsibility, as well as legal recourse, that healthcare facilities may exercise. This course will discuss policies and standards elating to health facility administration. Also included is a discussion of financial aspects unique to the hospital/ healthcare facility environment, such as third-party payments and federal assistance.', ARRAY[]::TEXT[], NULL),
    ('SPEA-H 352', 'HEALTHCARE FINANCIAL MANAGEMENT I', '7046', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'PV 278', 'Terri Renner', 7, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'First of a two-course sequence on the financial management of healthcare organizations; introduces financial environment of providers and concepts of financial accounting critical to decision-making. Topics include financial statement analysis (specific emphasis on unique features of healthcare financial statements), accounting and managerial control of cash, accounts receivable, inventory, and budgeting.', ARRAY[]::TEXT[], NULL),
    ('SPEA-H 352', 'HEALTHCARE FINANCIAL MANAGEMENT I', '30482', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'PV 277', 'Terri Renner', 2, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'First of a two-course sequence on the financial management of healthcare organizations; introduces financial environment of providers and concepts of financial accounting critical to decision-making. Topics include financial statement analysis (specific emphasis on unique features of healthcare financial statements), accounting and managerial control of cash, accounts receivable, inventory, and budgeting.', ARRAY[]::TEXT[], NULL),
    ('SPEA-H 353', 'HEALTHCARE FINANCIAL MANAGEMENT II', '2996', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'PV 274', 'Terri Renner', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Course focus is financial management of healthcare organizations; assessing critical decision-making concepts in managerial accounting and finance. Topics include evaluation of capital investments, financing sources, managerial accounting include cost behavior, profit analysis, and incremental analysis, reimbursement under various third-party payer environments, cost allocation and government program reporting.', ARRAY[]::TEXT[], NULL),
    ('SPEA-H 354', 'HEALTH ECONOMICS', '8991', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'PV 277', 'Kosali Simon', 2, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'Health economics studies the behavior of individuals, private and public employers, health care providers, and the government in decisions made within the health sphere. It applies microeconomics tools (including data analysis) to understand personal health behaviors, health care markets, health insurance systems, and health policies.', ARRAY[]::TEXT[], NULL),
    ('SPEA-H 365', 'HEALTH SERVICES PRACTICUM', '5487', 'Class Status', 'F Friday 9:00 AM–12:00 PM', 'WB WEB', 'Jean Scallon', 1, NULL, 'Practicum', '1', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'The Health Administration Practicum will consist of a personal career-planning component coupled with weekly field visits to health care agencies in Central Indiana. Students must perform satisfactorily in both parts of the practicum to receive a passing grade.', ARRAY[]::TEXT[], NULL),
    ('SPEA-H 365', 'HEALTH SERVICES PRACTICUM', '6492', 'Class Status', 'F Friday 9:00 AM–12:00 PM', 'WB WEB', 'Jean Scallon', 18, NULL, 'Practicum', '1', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'The Health Administration Practicum will consist of a personal career-planning component coupled with weekly field visits to health care agencies in Central Indiana. Students must perform satisfactorily in both parts of the practicum to receive a passing grade.', ARRAY[]::TEXT[], NULL),
    ('SPEA-H 374', 'HEALTH MANAGEMENT ETHICS', '11605', 'Class Status', 'TuTh Tuesday, Thursday 8:00 AM–9:15 AM', 'PV 274', 'Christopher Wayne', 10, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'This course examines healthcare ethical decision making challenges from managerial perspective and explores broader policy issues associated with ethical problems in healthcare institutions. It provides an overview of general theories of ethical challenges in everyday managerial activities.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-H 374', 'HEALTH MANAGEMENT ETHICS', '13961', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'LH 035', 'Julie Carmichael', 1, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'This course examines healthcare ethical decision making challenges from managerial perspective and explores broader policy issues associated with ethical problems in healthcare institutions. It provides an overview of general theories of ethical challenges in everyday managerial activities.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-H 401', 'STRATEGIC PLANNING IN HEALTH ORGANIZATIONS', '2997', 'Class Status', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'PV A221', 'Chuck Russo', 13, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'This course examines strategic planning techniques as it applies to healthcare organizations. Students will develop and defend a comprehensive strategic plan for a case facility. One half of the course will be conducted in a workshop format.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-H 402', 'HOSPITAL ADMINISTRATION', '11276', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'PV A335', 'Christopher Wayne', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'The study of organization, structure, function, and fiscal operations within hospitals. The role of the hospital in the community, relationship to official and voluntary health agencies, coordination of hospital departments, and managerial involvement will be examined.', ARRAY[]::TEXT[], NULL),
    ('SPEA-H 403', 'PHARMACEUTICAL INDUSTRY AND PUBLIC POLICY', '12948', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'PV A335', 'Julie Carmichael', 0, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'This course provides an overview of the pharmaceutical industry, its stakeholders and the key policy issues facing this industry. The course will focus on firms that operate in the traditional chemical pharmaceutical industry, biotechnology and medical devices. The course perspective is global, with an emphasis on the U.S. as the largest and most profitable market.', ARRAY[]::TEXT[], NULL),
    ('SPEA-H 411', 'CHRONIC AND LONG-TERM CARE ADMINISTRATION', '32241', 'Closed', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'M2 100', 'Natalie Peterson', 0, NULL, 'Lecture', '3', 'IU MUSEUM OF ARCHAEOLOGY & ANT', ARRAY[]::TEXT[], 'Administering programs across the continuum of care including nursing homes, hospice, home health, and assisted living; Medicare and Medicaid financing; quality improvement: care management; and needs of special populations, particularly, vulnerable elders.', ARRAY[]::TEXT[], NULL),
    ('SPEA-H 432', 'HEALTH CARE MARKETING', '12279', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'PV 276', 'Julie Carmichael', 3, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'A practical study of marketing in health care institutions, health service organizations, and health insurers. A basic foundation in marketing principles, new methods in marketing products and services, and inexpensive marketing techniques will be examined.', ARRAY['Class uses IU eTexts'], NULL),
    ('SPEA-H 455', 'TOPICS IN PUBLIC HEALTH', '10629', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'GY 1050', 'Julie Duhon', 3, NULL, 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'Extensive discussion of selected topics in public health. The topics may change from semester to semester with resource availability and student demand.', ARRAY['Class uses IU eTexts'], NULL)
